// NAME: Looping Symmetrical Edge Lights
uniform float light_height; // @min 0.05 @max 1.0 @default 0.3
uniform float light_size; // @min 0.1 @max 3.0 @default 1.2
uniform float light_intensity; // @min 0.5 @max 5.0 @default 2.0
uniform float loop_speed; // @min 0.1 @max 5.0 @default 1.0
uniform float edge_sensitivity; // @min 0.1 @max 20.0 @default 10.0
uniform float threshold_black; // @min 0.0 @max 1.0 @default 0.05
uniform float threshold_white; // @min 0.0 @max 1.0 @default 0.5
uniform float bump_strength; // @min 0.01 @max 0.2 @default 0.1
uniform float shininess; // @min 1.0 @max 64.0 @default 32.0
uniform vec3 light_color; // @default 1.0,0.9,0.8

float getLuma(vec3 rgb) {
    return dot(rgb, vec3(0.299, 0.587, 0.114));
}

vec3 calculatePointLight(vec3 lp, vec3 p, vec3 normal, vec3 viewDir, vec3 sourceRGB, float size, float intensity, float shiny, vec3 lCol) {
    vec3 lightDir = normalize(lp - p);
    vec3 reflectDir = reflect(-lightDir, normal);
    float dist = distance(lp, p);
    float atten = pow(clamp(1.0 - dist / size, 0.0, 1.0), 2.0);
    float diff = max(dot(normal, lightDir), 0.0);
    float spec = pow(max(dot(viewDir, reflectDir), 0.0), shiny);
    return (diff * sourceRGB + spec) * lCol * atten * intensity;
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 texel = 1.0 / resolution;
    vec4 source = texture2D(tex, uv);

    // Edge detection via luminance gradients
    float h = getLuma(source.rgb);
    float hR = getLuma(texture2D(tex, uv + vec2(texel.x, 0.0)).rgb);
    float hL = getLuma(texture2D(tex, uv - vec2(texel.x, 0.0)).rgb);
    float hU = getLuma(texture2D(tex, uv + vec2(0.0, texel.y)).rgb);
    float hD = getLuma(texture2D(tex, uv - vec2(0.0, texel.y)).rgb);

    float gx = hR - hL;
    float gy = hU - hD;

    // Edge mask based on thresholds
    float edgeRaw = length(vec2(gx, gy)) * edge_sensitivity;
    float edgeMask = smoothstep(threshold_black, threshold_white, edgeRaw);

    // Surface normal for lighting
    vec3 normal = normalize(vec3(-gx, -gy, bump_strength));
    vec3 p = vec3(uv, 0.0);
    vec3 viewDir = vec3(0.0, 0.0, 1.0);

    // Looping back and forth movement using sine waves
    float t = time * loop_speed;
    float lx = 0.5 + sin(t) * 0.4;
    float ly = 0.5 + cos(t * 0.7) * 0.4;

    // Light 1 position
    vec3 lp1 = vec3(lx, ly, light_height);

    // Symmetrical Light 2 position (mirrored across the center 0.5, 0.5)
    vec3 lp2 = vec3(1.0 - lx, 1.0 - ly, light_height);

    // Calculate lighting for both symmetrical sources
    vec3 light1 = calculatePointLight(lp1, p, normal, viewDir, source.rgb, light_size, light_intensity, shininess, light_color);
    vec3 light2 = calculatePointLight(lp2, p, normal, viewDir, source.rgb, light_size, light_intensity, shininess, light_color);

    // Combine lights and apply the edge threshold mask
    vec3 finalRGB = (light1 + light2) * edgeMask;

    // Add a subtle ambient glow to the edges to maintain visibility
    finalRGB += source.rgb * edgeMask * 0.05;

    return vec4(finalRGB, source.a);
}

