// NAME: Grid Drive Color Range
uniform vec3 target_color; // @default 0.0,0.0,0.0
uniform float color_threshold; // @min 0.0 @max 2.0 @default 0.3
uniform float color_smoothness; // @min 0.001 @max 1.0 @default 0.1

#define PI 3.141592654

mat2 rot(float x) {
    return mat2(cos(x), sin(x), -sin(x), cos(x));
}

vec2 foldRotate(in vec2 p, in float s) {
    float a = PI / s - atan(p.x, p.y);
    float n = PI * 2.0 / s;
    a = floor(a / n) * n;
    p *= rot(a);
    return p;
}

float sdRect(vec2 p, vec2 b) {
    vec2 d = abs(p) - b;
    return min(max(d.x, d.y), 0.0) + length(max(d, 0.0));
}

float tex_func(vec2 p, float z) {
    p = foldRotate(p, 8.0);
    vec2 q = (fract(p / 10.0) - 0.5) * 10.0;
    for (int i = 0; i < 3; ++i) {
        for(int j = 0; j < 2; j++) {
            q = abs(q) - 0.25;
            q *= rot(PI * 0.25);
        }
        q = abs(q) - vec2(1.0, 1.5);
        q *= rot(PI * 0.25 * z);
        q = foldRotate(q, 3.0);  
    }
    float d = sdRect(q, vec2(1.0, 1.0));
    float f = 1.0 / (1.0 + abs(d));
    return smoothstep(0.9, 1.0, f);
}

float Bokeh(vec2 p, vec2 sp, float size, float mi, float blur) {
    float d = length(p - sp);
    float c = smoothstep(size, size * (1.0 - blur), d);
    c *= mix(mi, 1.0, smoothstep(size * 0.8, size, d));
    return c;
}

vec2 hash(vec2 p) {
    p = vec2(dot(p, vec2(127.1, 311.7)), dot(p, vec2(269.5, 183.3)));
    return fract(sin(p) * 43758.5453) * 2.0 - 1.0;
}

float dirt(vec2 uv, float n) {
    vec2 p = fract(uv * n);
    vec2 st = (floor(uv * n) + 0.5) / n;
    vec2 rnd = hash(st);
    return Bokeh(p, vec2(0.5) + vec2(0.2) * rnd, 0.05, abs(rnd.y * 0.4) + 0.3, 0.25 + rnd.x * rnd.y * 0.2);
}

float sm(float start, float end, float t, float smo) {
    return smoothstep(start, start + smo, t) - smoothstep(end - smo, end, t);
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);

    // Calculate distance from current pixel color to the target color
    float dist = distance(source.rgb, target_color);

    // Mask to apply effect only within the chosen color range threshold
    float mask = 1.0 - smoothstep(color_threshold, color_threshold + color_smoothness, dist);

    if (mask <= 0.0) {
        return source;
    }

    vec2 p_uv = uv * 2.0 - 1.0;
    p_uv.x *= resolution.x / resolution.y;
    p_uv *= 2.0;

    vec3 col = vec3(0.0);
    float INTERVAL = 3.0;

    for(int i = 0; i < 6; i++) {
        float ii = float(6 - i);

        float t1 = ii * INTERVAL - mod(time - INTERVAL * 0.75, INTERVAL);
        vec3 I1 = vec3((18.0 - t1) / 18.0);
        col = mix(col, I1, dirt(mod(p_uv * max(0.0, t1) * 0.1 + vec2(0.2, -0.2) * time, 1.2), 3.5));

        float t2 = ii * INTERVAL - mod(time + INTERVAL * 0.5, INTERVAL);
        vec3 I2 = vec3((18.0 - t2) / 18.0);
        col = mix(col, I2 * vec3(0.7, 0.8, 1.0) * 1.3, tex_func(p_uv * max(0.0, t2), 4.45));

        float t3 = ii * INTERVAL - mod(time - INTERVAL * 0.25, INTERVAL);
        vec3 I3 = vec3((18.0 - t3) / 18.0);
        col = mix(col, I3, dirt(mod(p_uv * max(0.0, t3) * 0.1 + vec2(-0.2, -0.2) * time, 1.2), 3.5));

        float t4 = ii * INTERVAL - mod(time, INTERVAL);
        vec3 I4 = vec3((18.0 - t4) / 18.0);
        float r = length(p_uv * 2.0 * max(0.0, t4));
        float rr = sm(-24.0, 0.0, (r - mod(time * 30.0, 90.0)), 10.0);
        col = mix(col, mix(I4, I4 * vec3(0.7, 0.5, 1.0) * 3.0, rr), tex_func(p_uv * 2.0 * max(0.0, t4), 0.27 + (2.0 * rr)));
    }

    return mix(source, vec4(col, source.a), mask);
}

