// NAME: Color Strobe
uniform vec3 target_color; // @default 0.0,0.0,0.0
uniform float color_threshold; // @min 0.0 @max 2.0 @default 0.3
uniform float color_smoothness; // @min 0.001 @max 1.0 @default 0.1
uniform float strobe_speed; // @min 0.1 @max 50.0 @default 10.0
uniform vec3 strobe_color; // @default 1.0,1.0,1.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);

    // Calculate distance from current pixel color to the target color
    float dist = distance(source.rgb, target_color);

    // Mask to apply effect only within the chosen color range threshold
    float mask = 1.0 - smoothstep(color_threshold, color_threshold + color_smoothness, dist);

    // Generate a hard strobe effect (0.0 or 1.0)
    float strobe = step(0.5, fract(time * strobe_speed));

    // Mix the original color with the strobe color based on the mask and strobe state
    vec3 final_color = mix(source.rgb, strobe_color, mask * strobe);

    return vec4(final_color, source.a);
}

