}

vec3 calculatePointLight(vec3 lp, vec3 p, vec3 normal, vec3 viewDir, vec3 sourceRGB, float size, float intensity, float shiny, vec3 lCol) {
    vec3 lightDir = normalize(lp - p);
    vec3 reflectDir = reflect(-lightDir, normal);
    float dist = distance(lp, p);
    float atten = pow(clamp(1.0 - dist / size, 0.0, 1.0), 2.0);
    float diff = max(dot(normal, lightDir), 0.0);
    float spec = pow(max(dot(viewDir, reflectDir), 0.0), shiny);
    return (diff * sourceRGB + spec) * lCol * atten * intensity;
