// NAME: Seamless Soft Psychedelic Halo
uniform float intensity; // @min 0.0 @max 5.0 @default 2.5
uniform vec3 tint; // @default 0.1,0.5,0.9
uniform float haloSize; // @min 0.0 @max 1.0 @default 0.6
uniform float haloSoftness; // @min 0.01 @max 1.0 @default 0.5
uniform float warp; // @min 0.0 @max 5.0 @default 1.5

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 original = texture2D(tex, fract(uv));
    vec2 off = 2.0 / max(resolution, vec2(1.0));

    float lum = dot(original.rgb, vec3(0.299, 0.587, 0.114));
    lum += dot(texture2D(tex, fract(uv + vec2(off.x, off.y))).rgb, vec3(0.299, 0.587, 0.114));
    lum += dot(texture2D(tex, fract(uv + vec2(-off.x, off.y))).rgb, vec3(0.299, 0.587, 0.114));
    lum += dot(texture2D(tex, fract(uv + vec2(off.x, -off.y))).rgb, vec3(0.299, 0.587, 0.114));
    lum += dot(texture2D(tex, fract(uv + vec2(-off.x, -off.y))).rgb, vec3(0.299, 0.587, 0.114));
    lum *= 0.2;

    float dynamicHaloSize = clamp(haloSize, 0.01, 0.99);
    float darkHaloMask = smoothstep(max(0.0, dynamicHaloSize - haloSoftness), dynamicHaloSize, lum) *
                         (1.0 - smoothstep(dynamicHaloSize, dynamicHaloSize + haloSoftness, lum));

    // Use seamless trigonometric functions instead of node_noise to prevent seams
    vec2 uvWrap = uv * 6.28318530718;
    vec2 flow = vec2(
        sin(uvWrap.x * 2.0 + cos(uvWrap.y * 2.0)),
        cos(uvWrap.y * 2.0 + sin(uvWrap.x * 2.0))
    ) * warp * 0.25;

    float blobNoise = sin(uvWrap.x * 3.0 + flow.x * 5.0) * cos(uvWrap.y * 3.0 + flow.y * 5.0);
    float phase = lum + blobNoise * 0.5 + flow.x * 0.5 + flow.y * 0.5;

    vec3 psychColor = 0.5 + 0.5 * cos(6.28318530718 * (vec3(phase) + tint + vec3(0.02, 0.20, 0.38)));

    vec3 finalColor = clamp(psychColor * darkHaloMask * intensity, 0.0, 1.0);

    return vec4(finalColor, original.a);
}

