// NAME: Horizontal Band Loop
uniform float bands; // @min 1.0 @max 100.0 @default 20.0
uniform float speed; // @min 0.0 @max 5.0 @default 1.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    // Divide the image into horizontal bands (rows)
    float bandIndex = floor(uv.y * bands);

    // Generate a pseudo-random value for each band to vary speed and direction
    float randVal = node_rand(vec2(bandIndex, 1.0));
    float direction = randVal > 0.5 ? 1.0 : -1.0;

    vec2 newUV = uv;
    // Shift the x coordinate horizontally in a continuous loop
    newUV.x = fract(newUV.x + time * speed * direction * randVal);

    return texture2D(tex, newUV);
}

