// NAME: Normal Eyes High Contrast
uniform float tolerance; // @min -0.5 @max 1.0 @default 0.05
uniform float pupilSize; // @min 0.0 @max 0.5 @default 0.10
uniform float gridScale; // @min 1.0 @max 50.0 @default 12.0
uniform float moveSpeed; // @min 0.0 @max 5.0 @default 2.0
uniform float amountofmovement; // @min 0.0 @max 1.0 @default 0.5
uniform float contrast; // @min -5.0 @max 5.0 @default 2.5
uniform vec3 pupilColor; // @default 0.0,0.0,0.0
uniform vec3 irisColor; // @default 0.2,0.5,0.8

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);

    // Apply contrast to the base image (can be negative to invert)
    vec3 contrasted = clamp((source.rgb - 0.5) * contrast + 0.5, 0.0, 1.0);

    // Isolate green pixels to use as the eye mask
    float greenness = source.g - max(source.r, source.b);
    float mask = smoothstep(tolerance, tolerance + 0.1, greenness);

    // Simulate eyes looking around using offset sine waves
    float t = time * moveSpeed;
    vec2 lookOffset = vec2(
        sin(t) * 0.3 + cos(t * 0.73) * 0.2,
        cos(t * 1.1) * 0.3 + sin(t * 0.87) * 0.2
    ) * amountofmovement;

    // Generate a moving grid for the eyes
    vec2 gridUv = fract(uv * gridScale + lookOffset) - 0.5;
    float dist = length(gridUv);

    // Create pupil and iris shapes
    float pupil = 1.0 - smoothstep(pupilSize - 0.02, pupilSize + 0.02, dist);
    float irisSize = pupilSize * 2.2;
    float iris = 1.0 - smoothstep(irisSize - 0.02, irisSize + 0.02, dist);

    // Build the eye: White sclera -> Iris -> Pupil
    vec3 eyeColor = mix(vec3(1.0), irisColor, iris);
    eyeColor = mix(eyeColor, pupilColor, pupil);

    // Replace the green masked areas with the new eye, keep contrasted background elsewhere
    vec3 finalColor = mix(contrasted, eyeColor, mask);

    return vec4(finalColor, source.a);
}

