// NAME: Tri-State Wave Reveal
uniform float intensity; // @min 0.0 @max 5.0 @default 1.5
uniform vec3 tint; // @default 0.1,0.5,0.9
uniform float warp; // @min 0.0 @max 5.0 @default 1.5
uniform float speed; // @min 0.0 @max 5.0 @default 1.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 original = texture2D(tex, uv);
    float t = time * speed;

    // State 1: Inverted
    vec3 c1 = 1.0 - original.rgb;

    // State 2: Dark Normal
    vec3 c2 = original.rgb * 0.25;

    // State 3: Psychedelic
    vec2 uvWrap = uv * 6.28318530718;
    vec2 flow = vec2(
        sin(uvWrap.x * 2.0 + cos(uvWrap.y * 2.0 + t)),
        cos(uvWrap.y * 2.0 + sin(uvWrap.x * 2.0 - t))
    ) * warp * 0.25;
    float lum = dot(original.rgb, vec3(0.299, 0.587, 0.114));
    float blobNoise = sin(uvWrap.x * 3.0 + flow.x * 5.0 + t * 1.5) * cos(uvWrap.y * 3.0 + flow.y * 5.0 - t * 1.2);
    float phase = lum + blobNoise * 0.5 + flow.x * 0.5 + flow.y * 0.5 - t * 0.5;
    vec3 c3 = 0.5 + 0.5 * cos(6.28318530718 * (vec3(phase) + tint + vec3(0.0, 0.33, 0.67)));
