    // Random Wave Generation
    float waveBase = sin(uv.x * 8.0 + t) + cos(uv.y * 7.0 - t * 1.1) + sin((uv.x - uv.y) * 5.0 + t * 0.8);
    float noise = fract(sin(dot(uv, vec2(12.9898, 78.233))) * 43758.5453);
    float wave = mod((waveBase + 3.0) * 0.5 + noise * 0.5 + t * 0.5, 3.0);

