    vec3 finalColor;
    if (wave < 1.0) {
        finalColor = mix(c3, c1, smoothstep(0.0, 1.0, wave));
    } else if (wave < 2.0) {
        finalColor = mix(c1, c2, smoothstep(1.0, 2.0, wave));
    } else {
        finalColor = mix(c2, c3, smoothstep(2.0, 3.0, wave));
    }

    return vec4(clamp(finalColor, 0.0, 1.0), original.a);
}

