uniform float whiteSoftLight; // @min 0.0 @max 1.0 @default 0.5
uniform float whitesoftlighttreshold; // @min 0.0 @max 1.0 @default 0.5

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    // Apply symmetry across the Y axis (mirroring left and right)
    vec2 symUv = uv;
    symUv.x = abs(symUv.x - 0.5) + 0.5;

    vec4 original = texture2D(tex, fract(symUv));
    vec2 off = 2.0 / max(resolution, vec2(1.0));

    float lum = dot(original.rgb, vec3(0.299, 0.587, 0.114));
    lum += dot(texture2D(tex, fract(symUv + vec2(off.x, off.y))).rgb, vec3(0.299, 0.587, 0.114));
    lum += dot(texture2D(tex, fract(symUv + vec2(-off.x, off.y))).rgb, vec3(0.299, 0.587, 0.114));
    lum += dot(texture2D(tex, fract(symUv + vec2(off.x, -off.y))).rgb, vec3(0.299, 0.587, 0.114));
    lum += dot(texture2D(tex, fract(symUv + vec2(-off.x, -off.y))).rgb, vec3(0.299, 0.587, 0.114));
    lum *= 0.2;

    float dynamicHaloSize = clamp(haloSize, 0.01, 0.99);

    // Continuous loop back and forth for the halo softness
    float animSoftness = max(0.01, haloSoftness * (0.5 + 0.5 * sin(time * speed * 2.0)));

    float darkHaloMask = smoothstep(max(0.0, dynamicHaloSize - animSoftness), dynamicHaloSize, lum) *
                         (1.0 - smoothstep(dynamicHaloSize, dynamicHaloSize + animSoftness, lum));

    // Use seamless trigonometric functions and animate with time
    vec2 uvWrap = symUv * 6.28318530718;
    float t = time * speed;

    vec2 flow = vec2(
        sin(uvWrap.x * 2.0 + cos(uvWrap.y * 2.0 + t)),
        cos(uvWrap.y * 2.0 + sin(uvWrap.x * 2.0 - t))
    ) * warp * 0.25;

    float blobNoise = sin(uvWrap.x * 3.0 + flow.x * 5.0 + t * 1.5) * cos(uvWrap.y * 3.0 + flow.y * 5.0 - t * 1.2);
    float phase = lum + blobNoise * 0.5 + flow.x * 0.5 + flow.y * 0.5 - t * 0.5;

    vec3 psychColor = 0.5 + 0.5 * cos(6.28318530718 * (vec3(phase) + tint + vec3(0.02, 0.20, 0.38)));

    vec3 finalColor = clamp(psychColor * darkHaloMask * intensity, 0.0, 1.0);

    // Calculate colorfulness (saturation) of the original pixel
    float cMax = max(max(original.r, original.g), original.b);
    float cMin = min(min(original.r, original.g), original.b);
    float saturation = cMax - cMin;

    // Apply white soft light to more colored pixels based on the new parameter and threshold
    float glowAmount = smoothstep(whitesoftlighttreshold, whitesoftlighttreshold + 0.1, saturation);
    float glow = glowAmount * whiteSoftLight;
    finalColor = finalColor + (vec3(1.0) - finalColor) * glow;

