    float distMult = currentPixelDist * 5.0 + 0.1;
    float minDist = 100.0;

    for(int i = -4; i <= 4; i++) {
        for(int j = -4; j <= 4; j++) {
            float d2 = float(i * i + j * j);
            if (d2 <= 16.0) {
