// NAME: 3D Sculpture Spotlight
uniform float light_height; // @min 0.05 @max 1.0 @default 0.3
uniform float light_size; // @min 0.1 @max 2.0 @default 0.8
uniform float bump_strength; // @min 0.001 @max 0.1 @default 0.03
uniform float shininess; // @min 1.0 @max 64.0 @default 32.0
uniform vec3 light_color; // @default 1.0,1.0,0.9

float getLuma(vec3 rgb) {
    return dot(rgb, vec3(0.299, 0.587, 0.114));
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 texel = 1.0 / resolution;
    vec4 source = texture2D(tex, uv);

    // Calculate surface normal using luminance as a heightmap
    float h = getLuma(source.rgb);
    float hR = getLuma(texture2D(tex, uv + vec2(texel.x, 0.0)).rgb);
    float hU = getLuma(texture2D(tex, uv + vec2(0.0, texel.y)).rgb);

    // Finite difference for normal estimation
    vec3 normal = normalize(vec3(h - hR, h - hU, bump_strength));

    // Animated light position circling above the center
    vec3 lp = vec3(0.5 + cos(time * 0.8) * 0.25, 0.5 + sin(time * 0.8) * 0.25, light_height);
    vec3 p = vec3(uv, 0.0);

    // Lighting vectors
    vec3 lightDir = normalize(lp - p);
    vec3 viewDir = vec3(0.0, 0.0, 1.0);
    vec3 reflectDir = reflect(-lightDir, normal);

    // Distance and Attenuation
    float dist = distance(lp, p);
    float atten = pow(clamp(1.0 - dist / light_size, 0.0, 1.0), 2.0);

    // Diffuse and Specular components
    float diff = max(dot(normal, lightDir), 0.0);
    float spec = pow(max(dot(viewDir, reflectDir), 0.0), shininess);

    // Combine lighting
    vec3 lighting = (diff * source.rgb + spec * 0.5) * light_color * atten;

    // Output illuminated part, rest is black (attenuation handles the falloff)
    return vec4(lighting, source.a);
}

// NAME: Edge-Following Spotlight
uniform float light_height; // @min 0.05 @max 1.0 @default 0.3
uniform float light_size; // @min 0.1 @max 2.0 @default 0.8
uniform float bump_strength; // @min 0.01 @max 0.2 @default 0.05
uniform float shininess; // @min 1.0 @max 64.0 @default 32.0
uniform vec3 light_color; // @default 1.0,1.0,0.9

float getLuma(vec3 rgb) {
    return dot(rgb, vec3(0.299, 0.587, 0.114));
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 texel = 1.0 / resolution;
    vec4 source = texture2D(tex, uv);

    // Sample neighbors for edge detection and normal estimation
    float h = getLuma(source.rgb);
    float hR = getLuma(texture2D(tex, uv + vec2(texel.x, 0.0)).rgb);
    float hL = getLuma(texture2D(tex, uv - vec2(texel.x, 0.0)).rgb);
    float hU = getLuma(texture2D(tex, uv + vec2(0.0, texel.y)).rgb);
    float hD = getLuma(texture2D(tex, uv - vec2(0.0, texel.y)).rgb);

    // Calculate gradients
    float gx = hR - hL;
    float gy = hU - hD;

    // Edge intensity (Sobel-lite)
    float edge = clamp(length(vec2(gx, gy)) * 4.0, 0.0, 1.0);

    // Surface normal based on the gradient
    // We use the gradient to create a "bump" effect specifically on edges
    vec3 normal = normalize(vec3(-gx, -gy, bump_strength));

    // Animated light position
    vec3 lp = vec3(0.5 + cos(time * 0.7) * 0.3, 0.5 + sin(time * 0.7) * 0.3, light_height);
    vec3 p = vec3(uv, 0.0);

    // Lighting vectors
    vec3 lightDir = normalize(lp - p);
    vec3 viewDir = vec3(0.0, 0.0, 1.0);
    vec3 reflectDir = reflect(-lightDir, normal);

    // Distance and Attenuation
    float dist = distance(lp, p);
    float atten = pow(clamp(1.0 - dist / light_size, 0.0, 1.0), 2.0);

    // Diffuse and Specular components
    float diff = max(dot(normal, lightDir), 0.0);
    float spec = pow(max(dot(viewDir, reflectDir), 0.0), shininess);

    // Combine lighting and mask it by the edge detection result
    // This ensures the light "follows" or highlights the edges of the image
    vec3 lighting = (diff * source.rgb + spec) * light_color * atten * edge;

    // Add a tiny bit of ambient edge to keep shapes visible
    lighting += source.rgb * edge * 0.05;

    return vec4(lighting, source.a);
}

// NAME: Random Edge Spotlight
uniform float light_height; // @min 0.05 @max 1.0 @default 0.3
uniform float light_size; // @min 0.1 @max 3.0 @default 1.5
uniform float light_intensity; // @min 0.5 @max 5.0 @default 1.5
uniform float random_speed; // @min 0.1 @max 2.0 @default 0.4
uniform float edge_sensitivity; // @min 0.1 @max 20.0 @default 8.0
uniform float edge_mask_strength; // @min 0.0 @max 1.0 @default 0.9
uniform float bump_strength; // @min 0.01 @max 0.2 @default 0.08
uniform float shininess; // @min 1.0 @max 64.0 @default 32.0
uniform vec3 light_color; // @default 1.0,0.95,0.8

float getLuma(vec3 rgb) {
    return dot(rgb, vec3(0.299, 0.587, 0.114));
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 texel = 1.0 / resolution;
    vec4 source = texture2D(tex, uv);

    // Edge detection and Normal estimation
    float h = getLuma(source.rgb);
    float hR = getLuma(texture2D(tex, uv + vec2(texel.x, 0.0)).rgb);
    float hL = getLuma(texture2D(tex, uv - vec2(texel.x, 0.0)).rgb);
    float hU = getLuma(texture2D(tex, uv + vec2(0.0, texel.y)).rgb);
    float hD = getLuma(texture2D(tex, uv - vec2(0.0, texel.y)).rgb);

    float gx = hR - hL;
    float gy = hU - hD;

    // Edge intensity based on gradient magnitude
    float edge = clamp(length(vec2(gx, gy)) * edge_sensitivity, 0.0, 1.0);

    // Surface normal derived from the image gradient
    vec3 normal = normalize(vec3(-gx, -gy, bump_strength));

    // Pseudo-random light movement using built-in noise
    // We use different seeds for X and Y to create a 2D path
    float lx = node_noise(vec2(time * random_speed, 12.34));
    float ly = node_noise(vec2(time * random_speed, 56.78));

    // Position the light in 3D space (UV coordinates + height)
    vec3 lp = vec3(lx, ly, light_height);
    vec3 p = vec3(uv, 0.0);

    // Lighting vectors
    vec3 lightDir = normalize(lp - p);
    vec3 viewDir = vec3(0.0, 0.0, 1.0);
    vec3 reflectDir = reflect(-lightDir, normal);

    // Distance-based attenuation
    float dist = distance(lp, p);
    float atten = pow(clamp(1.0 - dist / light_size, 0.0, 1.0), 2.0);

    // Diffuse and Specular calculation
    float diff = max(dot(normal, lightDir), 0.0);
    float spec = pow(max(dot(viewDir, reflectDir), 0.0), shininess);

    // Combine lighting components
    vec3 lighting = (diff * source.rgb + spec) * light_color * atten * light_intensity;

    // Mask the light so it primarily follows the detected edges
    float mask = mix(1.0, edge, edge_mask_strength);
    vec3 finalColor = lighting * mask;

    // Add a subtle ambient edge glow to keep the structure visible
    finalColor += source.rgb * edge * 0.1;

    return vec4(finalColor, source.a);
}

// NAME: Edge-Threshold Random Spotlight
uniform float light_height; // @min 0.05 @max 1.0 @default 0.3
uniform float light_size; // @min 0.1 @max 3.0 @default 1.2
uniform float light_intensity; // @min 0.5 @max 5.0 @default 2.0
uniform float random_speed; // @min 0.1 @max 2.0 @default 0.5
uniform float edge_sensitivity; // @min 0.1 @max 20.0 @default 10.0
uniform float threshold_black; // @min 0.0 @max 1.0 @default 0.05
uniform float threshold_white; // @min 0.0 @max 1.0 @default 0.5
uniform float bump_strength; // @min 0.01 @max 0.2 @default 0.1
uniform float shininess; // @min 1.0 @max 64.0 @default 32.0
uniform vec3 light_color; // @default 1.0,0.9,0.8

float getLuma(vec3 rgb) {
    return dot(rgb, vec3(0.299, 0.587, 0.114));
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 texel = 1.0 / resolution;
    vec4 source = texture2D(tex, uv);

    // Edge detection via luminance gradients
    float h = getLuma(source.rgb);
    float hR = getLuma(texture2D(tex, uv + vec2(texel.x, 0.0)).rgb);
    float hL = getLuma(texture2D(tex, uv - vec2(texel.x, 0.0)).rgb);
    float hU = getLuma(texture2D(tex, uv + vec2(0.0, texel.y)).rgb);
    float hD = getLuma(texture2D(tex, uv - vec2(0.0, texel.y)).rgb);

    float gx = hR - hL;
    float gy = hU - hD;

    // Calculate raw edge intensity
    float edgeRaw = length(vec2(gx, gy)) * edge_sensitivity;

    // Apply user-defined black and white thresholds to the edge detection
    float edgeMask = smoothstep(threshold_black, threshold_white, edgeRaw);

    // Surface normal for lighting calculations
    vec3 normal = normalize(vec3(-gx, -gy, bump_strength));

    // Random light movement using built-in noise
    float lx = node_noise(vec2(time * random_speed, 100.0));
    float ly = node_noise(vec2(time * random_speed, 200.0));
    vec3 lp = vec3(lx, ly, light_height);
    vec3 p = vec3(uv, 0.0);

    // Lighting vectors
    vec3 lightDir = normalize(lp - p);
    vec3 viewDir = vec3(0.0, 0.0, 1.0);
    vec3 reflectDir = reflect(-lightDir, normal);

    // Attenuation based on distance from the random light source
    float dist = distance(lp, p);
    float atten = pow(clamp(1.0 - dist / light_size, 0.0, 1.0), 2.0);

    // Diffuse and Specular components
    float diff = max(dot(normal, lightDir), 0.0);
    float spec = pow(max(dot(viewDir, reflectDir), 0.0), shininess);

    // Combine lighting and constrain it to the edge mask
    // This makes the light "follow" or only appear on the detected edges
    vec3 lighting = (diff * source.rgb + spec) * light_color * atten * light_intensity;
    vec3 finalRGB = lighting * edgeMask;

    // Add a very subtle ambient glow to the edges for definition
    finalRGB += source.rgb * edgeMask * 0.02;

    return vec4(finalRGB, source.a);
}

// NAME: Symmetrical Edge Spotlights
