mat2 rot(float x) {
    return mat2(cos(x), sin(x), -sin(x), cos(x));
}

vec2 foldRotate(in vec2 p, in float s) {
    float a = PI / s - atan(p.x, p.y);
    float n = PI * 2.0 / s;
    return p * rot(floor(a / n) * n);
}

float tex_func(vec2 p, float z, float t, float sym, float dist) {
    p = foldRotate(p, sym);

    p *= rot(length(p) * dist * 0.05 + t * 0.3);

    vec2 q = (fract(p / 10.0) - 0.5) * 10.0;
    for (int i = 0; i < 2; ++i) {
