        q *= rot(PI * 0.25 + dist * 0.15 * sin(t * 0.8 + length(q)));
        q = abs(q) - vec2(1.0, 1.5);
        q *= rot(PI * 0.25 * z);
        q = foldRotate(q, 3.0);  
    }
    vec2 d = abs(q) - vec2(1.0);
    float sd = min(max(d.x, d.y), 0.0) + length(max(d, 0.0));
    return smoothstep(0.9, 1.0, 1.0 / (1.0 + abs(sd)));
