// NAME: Soft Symmetrical Scanner with Blurred Trace
uniform float rangeWidth; // @min 0.0 @max 1.0 @default 0.2
uniform float speed; // @min -2.0 @max 2.0 @default 0.5
uniform vec3 tintColor; // @default 1.0,0.5,0.0
uniform float edgeSoftness; // @min 0.001 @max 0.5 @default 0.05
uniform float borderSoftness; // @min 0.001 @max 1.0 @default 0.2
uniform float traceLength; // @min 0.0 @max 1.0 @default 0.3
uniform float whiteBlurAmount; // @min 0.0 @max 10.0 @default 3.0
uniform float blackThreshold; // @min 0.001 @max 0.5 @default 0.05
uniform float psychScale; // @min 1.0 @max 50.0 @default 20.0
uniform float psychIntensity; // @min 0.0 @max 1.0 @default 0.3
uniform float whiteOpacity; // @min 0.0 @max 5.0 @default 1.2

vec3 rgb2hsv(vec3 c) {
    vec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);
    vec4 p = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));
    vec4 q = mix(vec4(p.xyw, c.r), vec4(c.r, p.yzx), step(p.x, c.r));
    float d = q.x - min(q.w, q.y);
    float e = 1.0e-10;
    return vec3(abs(q.z + (q.w - q.y) / (6.0 * d + e)), d / (q.x + e), q.x);
}

vec3 hsv2rgb(vec3 c) {
    vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
    vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
    return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    // Make the UVs symmetrical horizontally
    vec2 symUv = vec2(uv.x > 0.5 ? 1.0 - uv.x : uv.x, uv.y);

    vec4 source = texture2D(tex, symUv);
    vec3 hsv = rgb2hsv(source.rgb);

    float targetHue = fract(time * speed);
    float signedDist = fract(hsv.x - targetHue + 0.5) - 0.5;
    float dist = abs(signedDist);

    // Soften the mask to remove pixelated artifacts
    float mask = smoothstep(rangeWidth * 0.5 + edgeSoftness, rangeWidth * 0.5, dist);

    float dir = speed >= 0.0 ? 1.0 : -1.0;

    // Calculate spatially blurred white border and trace
    float finalWhite = 0.0;
    float totalWeight = 0.0;
    vec2 texel = 1.0 / resolution;

    for(int i = -1; i <= 1; i++) {
        for(int j = -1; j <= 1; j++) {
            vec2 offset = vec2(float(i), float(j)) * whiteBlurAmount * texel * 2.0;
            vec2 sampleUv = symUv + offset;

            vec4 s = texture2D(tex, sampleUv);
            vec3 shsv = rgb2hsv(s.rgb);

            float sDistSigned = fract(shsv.x - targetHue + 0.5) - 0.5;
            float sDist = abs(sDistSigned);

            float b = smoothstep(borderSoftness, 0.0, abs(sDist - rangeWidth * 0.5));
            float t = smoothstep(rangeWidth * 0.5 + traceLength, rangeWidth * 0.5, sDist) * step(0.0, -sDistSigned * dir);

            float weight = 1.0 - (abs(float(i)) + abs(float(j))) * 0.25;
            finalWhite += max(b, t) * weight;
            totalWeight += weight;
        }
    }
    finalWhite /= totalWeight;

    // Parametric psychedelic shift
    float psychShift = sin(symUv.x * psychScale + time * 3.0) * psychIntensity + 
                       cos(symUv.y * psychScale - time * 2.0) * psychIntensity + time * 2.0;

    hsv.x = fract(hsv.x + psychShift);
    hsv.y = clamp(hsv.y * 1.5, 0.0, 1.0);

    vec3 psychColor = hsv2rgb(hsv);

    // Apply the selected tint color
    psychColor *= tintColor * 1.5; 

    // Combine the tinted psychedelic effect, the mask, and the blurred white border/trace with parametric opacity
    vec3 finalColor = psychColor * mask + vec3(1.0) * finalWhite * whiteOpacity;

    // Keep black pixels black smoothly to avoid hard jagged edges
    float blackMask = smoothstep(0.0, blackThreshold, hsv.z);
    finalColor *= blackMask;

    return vec4(clamp(finalColor, 0.0, 1.0), source.a);
}

