uniform float blackLineThickness; // @min 0.01 @max 2.0 @default 0.1
uniform float blackLineSpeed; // @min -5.0 @max 5.0 @default -1.0
uniform float blackLineBlur; // @min 0.0 @max 2.0 @default 0.5

#define R3 1.732051

vec4 HexCoords(vec2 uv) {
    vec2 s = vec2(1.0, R3);
    vec2 h = 0.5 * s;
    vec2 gv = s * uv;
    vec2 a = mod(gv, s) - h;
    vec2 b = mod(gv + h, s) - h;
    vec2 ab = dot(a, a) < dot(b, b) ? a : b;
    return vec4(ab, gv - ab);
}

float GetSize(vec2 id, float seed, float time) {
    float d = length(id);
    float t = time * 0.5;
    return (sin(d * seed + t) + sin(d * seed * seed * 10.0 + t * 2.0)) / 2.0 + 0.5;
}

mat2 Rot(float a) {
    float s = sin(a), c = cos(a);
    return mat2(c, -s, s, c);
}

float Hexagon(vec2 uv, float r, float time, float thickness, float blur) {
    uv *= Rot(mix(0.0, 3.1415, r));
    r /= 0.7071;
    uv = vec2(-uv.y, uv.x);
    uv.x *= R3;
    uv = abs(uv);
    float d = dot(uv, normalize(vec2(1.0, 1.0))) - r;
    d = max(d, uv.y - r * 0.707);

    float edge = smoothstep(0.06 * thickness + blur, 0.02 * thickness, abs(d));
    float glow = smoothstep(0.25 * thickness + blur, 0.0, abs(d)) * 2.5;

    return edge + glow + smoothstep(0.1 * thickness + blur, 0.09 * thickness, abs(r - 0.5)) * sin(time);
}

float Layer(vec2 uv, float s, float time, float thickness, float blur) {
    vec4 hu = HexCoords(uv * 2.0);
    float d = Hexagon(hu.xy, GetSize(hu.zw, s, time), time, thickness, blur);
    vec2 offs = vec2(1.0, 0.0);
    d += Hexagon(hu.xy - offs, GetSize(hu.zw + offs, s, time), time, thickness, blur);
    d += Hexagon(hu.xy + offs, GetSize(hu.zw - offs, s, time), time, thickness, blur);
    offs = vec2(0.5, 0.8725);
    d += Hexagon(hu.xy - offs, GetSize(hu.zw + offs, s, time), time, thickness, blur);
    d += Hexagon(hu.xy + offs, GetSize(hu.zw - offs, s, time), time, thickness, blur);
    offs = vec2(-0.5, 0.8725);
    d += Hexagon(hu.xy - offs, GetSize(hu.zw + offs, s, time), time, thickness, blur);
    d += Hexagon(hu.xy + offs, GetSize(hu.zw - offs, s, time), time, thickness, blur);
    return d;
}

float N(float p) {
    return fract(sin(p * 123.34) * 345.456);
}

vec3 Col(float p, float offs) {
