    vec2 p_uv = UV * mix(1.0, 5.0, sin(t * 0.5) * 0.5 + 0.5) * scale;
    p_uv *= Rot(t);
    p_uv.x *= R3;

    vec3 col = vec3(0.0);
    for(float i = 0.0; i < 1.0; i += 0.3333) {
