#define R3 1.732051

vec4 HexCoords(vec2 uv) {
    vec2 s = vec2(1, R3);
    vec2 h = .5*s;

    vec2 gv = s*uv;

    vec2 a = mod(gv, s)-h;
    vec2 b = mod(gv+h, s)-h;

    vec2 ab = dot(a,a)<dot(b,b) ? a : b;
    vec2 st = ab;
    vec2 id = gv-ab;

   // ab = abs(ab);
    //st.x = .5-max(dot(ab, normalize(s)), ab.x);
	st = ab;
    return vec4(st, id);
}

float GetSize(vec2 id, float seed) {
    float d = length(id);
    float t = iTime*.5;
    float a = sin(d*seed+t)+sin(d*seed*seed*10.+t*2.);
    return a/2. +.5;
}

mat2 Rot(float a) {
    float s = sin(a);
    float c = cos(a);
    return mat2(c, -s, s, c);
}

float Hexagon(vec2 uv, float r, vec2 offs) {

    uv *= Rot(mix(0., 3.1415, r));

    r /= 1./sqrt(2.);
    uv = vec2(-uv.y, uv.x);
    uv.x *= R3;
    uv = abs(uv);

    vec2 n = normalize(vec2(1,1));
