    p_uv *= Rot(t);
    p_uv.x *= R3;

    vec3 col = vec3(0.0);
    for(float i = 0.0; i < 1.0; i += 0.3333) {
        float id = floor(i + t);
        float ft = fract(i + t);
        float z = mix(5.0, 0.1, ft);
