    vec4 source = texture2D(tex, uv);
    vec2 UV = uv - 0.5;
    UV.x *= resolution.x / resolution.y;
    float duv = dot(UV, UV);

    vec3 col1 = GetAnimColor(UV, time, duv, 1.0, 0.0, 1.0);
    vec3 illuminatedColor = source.rgb * col1 * 2.0 * intensity;
    float illumFactor = clamp(length(col1 * intensity), 0.0, 1.0);

    vec3 invertedSource = 1.0 - source.rgb;
    float brightness = dot(source.rgb, vec3(0.299, 0.587, 0.114));
    invertedSource *= smoothstep(0.05, 0.2, brightness);

    vec3 effectColor = mix(invertedSource, illuminatedColor, illumFactor);
    vec3 finalColor = mix(source.rgb, effectColor, effectAmount);

    float whiteness = min(finalColor.r, min(finalColor.g, finalColor.b));
    float mask = smoothstep(0.8, 1.0, whiteness);

    if (mask > 0.0) {
        vec3 col2 = GetAnimColor(UV, time, duv, 1.0, 0.0, -1.0);
        vec3 reverseIlluminated = source.rgb * col2 * 2.0 * intensity;
        finalColor = mix(finalColor, reverseIlluminated, mask);
