float GetSize(vec2 id, float seed, float time) {
    float d = length(id);
    float t = time * 0.5;
    float a = sin(d * seed + t) + sin(d * seed * seed * 10.0 + t * 2.0);
    return a / 2.0 + 0.5;
}

mat2 Rot(float a) {
    float s = sin(a), c = cos(a);
    return mat2(c, -s, s, c);
