    vec4 hu = HexCoords(uv * 2.0);
    float d = Hexagon(hu.xy, GetSize(hu.zw, s, time), time);
    vec2 offs = vec2(1.0, 0.0);
    d += Hexagon(hu.xy - offs, GetSize(hu.zw + offs, s, time), time);
    d += Hexagon(hu.xy + offs, GetSize(hu.zw - offs, s, time), time);
    offs = vec2(0.5, 0.8725);
    d += Hexagon(hu.xy - offs, GetSize(hu.zw + offs, s, time), time);
    d += Hexagon(hu.xy + offs, GetSize(hu.zw - offs, s, time), time);
    offs = vec2(-0.5, 0.8725);
    d += Hexagon(hu.xy - offs, GetSize(hu.zw + offs, s, time), time);
    d += Hexagon(hu.xy + offs, GetSize(hu.zw - offs, s, time), time);
    return d;
}

float N(float p) {
    return fract(sin(p * 123.34) * 345.456);
}

vec3 Col(float p, float offs) {
    float n = N(p) * 1234.34;
    return sin(n * vec3(12.23, 45.23, 56.2) + offs * 3.0) * 0.5 + 0.5;
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);
    vec2 UV = uv - 0.5;
    UV.x *= resolution.x / resolution.y;
    float duv = dot(UV, UV);

    float t = time * speed * 0.5 + 5.0;
    vec2 p_uv = UV * mix(1.0, 5.0, sin(t * 0.5) * 0.5 + 0.5) * scale;
    p_uv *= Rot(t);
