    vec3 col = vec3(0.0);
    for(float i = 0.0; i < 1.0; i += 0.3333) {
        float id = floor(i + t);
        float ft = fract(i + t);
        float z = mix(5.0, 0.1, ft);
        float fade = smoothstep(0.0, 0.3, ft) * smoothstep(1.0, 0.7, ft);
        col += fade * ft * Layer(p_uv * z, N(i + id), time) * Col(id, duv);
