    float lum = dot(source.rgb, vec3(0.299, 0.587, 0.114));
    float mask = smoothstep(0.01, 0.05, lum);

    // Only show the original color where the hexagon effect is illuminating
    float illumination = clamp(length(col), 0.0, 1.0);
    vec3 finalColor = (source.rgb * illumination) + (col * mask);

    return vec4(clamp(finalColor, 0.0, 1.0), source.a);
