vec3 palette(float t){
    vec3 a = vec3(0.84, 0.49, 0.85);
    vec3 b = vec3(0.52, 0.56, 0.88);
    vec3 c = vec3(0.18, 0.40, 0.07);
    vec3 d = vec3(0.28, 0.68, 0.30);
