vec2 swirl(vec2 p, float strength, float freq, float speed, float time) {
    float r = length(p);
    float a = atan(p.y, p.x);
    float s = sin(speed * time + freq * r);
    a += strength * r * s;
    float w = sin(speed * time + freq * r);
    r += 0.06 * w;
    a += strength * r * w;
    w = sin(speed * time + freq * r + 3.0 * a);
    a += strength * r * w;
    return r * vec2(cos(a), sin(a));
