// NAME: Distorted LSD Snake
uniform float scale; // @min 1.0 @max 50.0 @default 10.0
uniform float speed; // @min 0.0 @max 5.0 @default 0.5
uniform float dash_freq; // @min 1.0 @max 20.0 @default 8.0
uniform float thickness; // @min 0.01 @max 0.5 @default 0.15
uniform float blur; // @min 0.0 @max 0.2 @default 0.05
uniform float distortion; // @min 0.0 @max 5.0 @default 1.5

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 bg = texture2D(tex, uv);

    // Mask to prevent the snake from appearing on black/dark pixels
    float luma = dot(bg.rgb, vec3(0.299, 0.587, 0.114));
    float isNotBlack = smoothstep(0.02, 0.1, luma);

    // Distance from center for distortion
    vec2 centerDist = uv - 0.5;
    float dist = length(centerDist);

    // Apply radial ripple distortion based on distance from center
    vec2 p = uv + centerDist * sin(dist * 15.0 - time * 3.0) * distortion * 0.1;

    // Snake pattern generation (global overlay)
    p.x = abs(p.x - 0.5); // Symmetry
    float dyn_scale = scale + sin(time * 0.5) * 2.0;
    p *= dyn_scale;

    vec2 ip = floor(p);
    vec2 fp = fract(p);

    float h = fract(sin(dot(ip, vec2(12.9898, 78.233))) * 43758.5453);
    if (h > 0.5) {
        fp.x = 1.0 - fp.x;
    }

    float d1 = length(fp);
    float d2 = length(fp - vec2(1.0));
    float d = min(abs(d1 - 0.5), abs(d2 - 0.5));

    // Pulsing thickness
    float dyn_thick = thickness + sin(time * 3.0) * 0.02;
    float path = smoothstep(dyn_thick, dyn_thick - blur, d);

    float arcLen = min(d1, d2);
    float dash = step(0.5, fract((arcLen - time * speed) * dash_freq));

    // Apply the black pixel mask to the snake body
    float mask = path * dash * isNotBlack;

    // 3D tube effect for the snake body
    float nx = clamp(d / dyn_thick, 0.0, 1.0);
    float nz = sqrt(1.0 - nx * nx);

    // LSD Psychedelic Color Stripes affected by the original image color
    vec3 lsdColor = 0.5 + 0.5 * cos(time * 5.0 - arcLen * 25.0 + vec3(0.0, 2.0, 4.0));
    lsdColor = clamp(lsdColor * bg.rgb * 2.0, 0.0, 1.0);

    vec3 snakeColor = lsdColor * nz; // Base tube color
    snakeColor += lsdColor * pow(nz, 4.0); // Glowing core

    // Add a glowing aura bleeding into the background, also masked by black pixels
    float glow = smoothstep(dyn_thick + 0.2, dyn_thick, d) * dash * isNotBlack;

    // Make all pixels black unless illuminated by the snake's glow
    vec3 bgWithGlow = (bg.rgb * glow) + (lsdColor * glow * 0.8);

    // Composite the snake completely on top of everything
    vec3 finalColor = mix(bgWithGlow, snakeColor, mask);

    return vec4(finalColor, bg.a);
}

