uniform float snakeSpeed; // @min -10.0 @max 10.0 @default 5.0
uniform float snakeTiling; // @min 1.0 @max 20.0 @default 3.0
uniform float lineThickness; // @min 0.01 @max 0.5 @default 0.15
uniform float zoneThreshold; // @min 0.0 @max 1.0 @default 0.8
uniform float minZoneThreshold; // @min 0.0 @max 1.0 @default 0.2
uniform float loopSpeed; // @min -5.0 @max 5.0 @default 1.0
uniform float pixelSoftness; // @min 0.01 @max 3.0 @default 1.8
uniform float colorSpeed; // @min 0.0 @max 10.0 @default 2.0
uniform float psychedelicScale; // @min 1.0 @max 20.0 @default 5.0
uniform bool showBackground; // @default true
uniform float blobSize; // @min 0.1 @max 2.0 @default 0.6
uniform float blobBlur; // @min 0.1 @max 2.0 @default 0.8

float getMask(sampler2D tex, vec2 uv, vec2 res, float t, float lc, float lt, float ps, float zt, float st, float ss, float ls) {
    vec3 lw = vec3(0.299, 0.587, 0.114);
    float lum = dot(texture2D(tex, uv).rgb, lw);
    vec2 eps = vec2(3.0) / res;
    float lumX = dot(texture2D(tex, uv + vec2(eps.x, 0.0)).rgb, lw);
    float lumY = dot(texture2D(tex, uv + vec2(0.0, eps.y)).rgb, lw);
    vec2 grad = vec2(lumX - lum, lumY - lum);
    float angle = atan(grad.y, grad.x + 0.0001);

    float iso = fract(lum * lc - t * ls);
    float soft = lt * ps * 1.5;
    float line = smoothstep(zt - soft, zt, iso) - smoothstep(zt, zt + soft, iso);
    line *= smoothstep(0.001, 0.02, length(grad));

    float snake = sin(angle * st * 2.0 + t * ss);
    return line * smoothstep(-1.2 * ps, 1.2, snake);
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);

    float currentZT = mix(minZoneThreshold, zoneThreshold, sin(time * loopSpeed) * 0.5 + 0.5);

    float m0 = getMask(tex, uv, resolution, time, linesCount, lineThickness, pixelSoftness, currentZT, snakeTiling, snakeSpeed, loopSpeed);

    vec2 eps = vec2(4.0) / resolution;
    float mx = getMask(tex, uv + vec2(eps.x, 0.0), resolution, time, linesCount, lineThickness, pixelSoftness, currentZT, snakeTiling, snakeSpeed, loopSpeed);
    float my = getMask(tex, uv + vec2(0.0, eps.y), resolution, time, linesCount, lineThickness, pixelSoftness, currentZT, snakeTiling, snakeSpeed, loopSpeed);

    vec3 n = normalize(vec3(m0 - mx, m0 - my, 0.25));

    vec3 lightDir = normalize(vec3(0.8, 0.8, 1.0));
    float diff = max(dot(n, lightDir), 0.0);
    float diffSoft = diff * 0.6 + 0.4; 

    vec3 viewDir = vec3(0.0, 0.0, 1.0);
    vec3 halfDir = normalize(lightDir + viewDir);

    float spec = pow(max(dot(n, halfDir), 0.0), 12.0) * m0 * 0.6;
    float fresnel = pow(1.0 - max(dot(n, viewDir), 0.0), 2.5) * m0;

    vec3 darkGradient = vec3(0.02, 0.04, 0.08) * (1.5 - length(uv - 0.5) * 1.5);
    vec3 bg = showBackground ? mix(source.rgb * 0.3, darkGradient, 0.5) : darkGradient;

    vec3 lw = vec3(0.299, 0.587, 0.114);
    float lum = dot(source.rgb, lw);
    vec2 epsGrad = vec2(3.0) / resolution;
    float lumX = dot(texture2D(tex, uv + vec2(epsGrad.x, 0.0)).rgb, lw);
    float lumY = dot(texture2D(tex, uv + vec2(0.0, epsGrad.y)).rgb, lw);
    vec2 grad = vec2(lumX - lum, lumY - lum);
    float angle = atan(grad.y, grad.x + 0.0001);

    float phase = angle * snakeTiling * 2.0 + time * snakeSpeed;

    float n1 = node_noise(uv * psychedelicScale + time);
    float n2 = node_noise(uv * psychedelicScale * 2.0 - time * 0.5 + n1 * 3.0);
    float r1 = node_rand(floor(uv * psychedelicScale * 5.0) + time * 0.1);

    vec3 trailColor = 0.5 + 0.5 * cos(phase * 0.5 - time * colorSpeed + n2 * 6.28 + vec3(0.0, 2.1, 4.2) + r1 * 1.5);

    vec3 finalColor = trailColor * diffSoft + spec + fresnel * vec3(0.8, 0.9, 1.0);
    vec3 mixedColor = mix(bg, finalColor, m0);

    vec2 centered = uv - 0.5;
    vec2 symUv = abs(centered);
    float blobNoise = node_noise(symUv * 5.0 - time * 0.3);
    float dist = length(centered) + blobNoise * 0.4;
    float blobMask = smoothstep(blobSize, blobSize - blobBlur, dist);

    mixedColor = mix(mixedColor, vec3(0.0), blobMask);

    return vec4(mixedColor, source.a);
}

