    float zoom = 1.0 + 0.6 * sin(time * 1.5);
    vec2 gridUv = vec2(abs(uv.x - 0.5), uv.y);
    gridUv = (gridUv - vec2(0.25, 0.5)) * zoom + vec2(0.25, 0.5);
    gridUv.y -= time * gridSpeed; 
    gridUv += vec2(sin(gridUv.y * 15.0 + time), cos(gridUv.x * 15.0 + time)) * gridDistortion; 

