    float gridY = sin(gridUv.y * gridScale);
    float dots = (gridX * gridY) * 0.5 + 0.5;

    float dotSize = 0.5 + 0.45 * sin(time * 3.0);
    float moire = smoothstep(1.0 - dotSize, 1.0 - dotSize + 0.1, dots);

    float mask = mix(1.0 - gridIntensity, 1.0 + gridIntensity, moire);
    finalColor.rgb *= mask;

    return finalColor;
