uniform float edgeWidth; // @min 0.5 @max 5.0 @default 1.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 texel = edgeWidth / resolution;

    vec4 c = texture2D(tex, uv);
    vec4 n = texture2D(tex, uv + vec2(0.0, texel.y));
    vec4 s = texture2D(tex, uv - vec2(0.0, texel.y));
    vec4 e = texture2D(tex, uv + vec2(texel.x, 0.0));
    vec4 w = texture2D(tex, uv - vec2(texel.x, 0.0));

    // Calculate difference between center and neighbors
    vec4 diff = abs(c - n) + abs(c - s) + abs(c - e) + abs(c - w);
    float edge = length(diff.rgb) + diff.a;

    // Determine if current pixel is on an edge
    float isEdge = step(edgeThreshold, edge);

    // Create a white-tinted version of the original color
    vec4 tinted = mix(c, vec4(1.0, 1.0, 1.0, c.a), tintAmount);

    // Output original color on edges, tinted color elsewhere
    return mix(tinted, c, isEdge);
}

