// NAME: Edge Flowing Rotating Fat Dots
uniform float speed; // @min -10.0 @max 10.0 @default 5.0
uniform float dotDensity; // @min 10.0 @max 100.0 @default 40.0
uniform float dotSize; // @min 0.1 @max 1.0 @default 0.7
uniform float edgeThickness; // @min 1.0 @max 10.0 @default 3.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 baseColor = texture2D(tex, uv);

    // Scale the offset by edgeThickness to create a wider "edge zone"
    vec2 off = (1.0 / resolution) * edgeThickness;

    // Sample 8 neighboring pixels for edge detection (using the red channel for luminance)
    float t00 = texture2D(tex, uv + vec2(-off.x, -off.y)).r;
    float t10 = texture2D(tex, uv + vec2( 0.0,   -off.y)).r;
    float t20 = texture2D(tex, uv + vec2( off.x, -off.y)).r;
    float t01 = texture2D(tex, uv + vec2(-off.x,  0.0)).r;
    float t21 = texture2D(tex, uv + vec2( off.x,  0.0)).r;
    float t02 = texture2D(tex, uv + vec2(-off.x,  off.y)).r;
    float t12 = texture2D(tex, uv + vec2( 0.0,    off.y)).r;
    float t22 = texture2D(tex, uv + vec2( off.x,  off.y)).r;

    // Apply Sobel operators
    float gx = (t00 + 2.0 * t01 + t02) - (t20 + 2.0 * t21 + t22);
    float gy = (t00 + 2.0 * t10 + t20) - (t02 + 2.0 * t12 + t22);

    // Calculate edge intensity
    float edge = length(vec2(gx, gy));

    // Soften and expand the edge mask to create a walkable "zone" for the dots
    float edgeZone = smoothstep(0.1, 0.6, edge);

    // The Normal vector points ACROSS the edge. 
    // The Tangent vector points ALONG the edge. Adding a tiny fraction avoids division by zero.
    vec2 tangent = normalize(vec2(-gy, gx) + 0.00001);
    vec2 normal = normalize(vec2(gx, gy) + 0.00001);

    // 1. Calculate movement traveling along the edge path
    float travelPos = dot(uv, tangent) * dotDensity + (time * speed);

    // 2. Calculate the cross-section coordinate (across the edge thickness)
    float crossPos = dot(uv, normal) * dotDensity;

    // Combine into a local 2D coordinate system aligned with the edge
    vec2 localSpace = vec2(travelPos, crossPos);

    // Create a rotation matrix based on time to make the dots rotate/tumble
    float spin = time * speed * 1.5;
    float s = sin(spin);
    float c = cos(spin);
    mat2 rotMatrix = mat2(c, -s, s, c);

    // Apply the rotation to our local edge-aligned space
    vec2 rotatedSpace = rotMatrix * localSpace;

    // Generate the blob/dot shape using intersecting sine waves on the rotated space
    float dotPattern = sin(rotatedSpace.x) * sin(rotatedSpace.y);

    // Threshold the pattern to create isolated, "fat" dots. 
    // A wider smoothstep based on dotSize makes them larger and thicker.
    float dots = smoothstep(1.0 - dotSize, 1.0 - dotSize + 0.15, dotPattern);

    // Constrain the dots strictly to the edge zone
    float finalMask = dots * edgeZone;

    // Soft light base from the original image (dimmed to make dots pop)
    vec3 softLight = baseColor.rgb * 0.3;

    // Highlight lines colored based on the original image color (brightened)
    vec3 dotColor = clamp(baseColor.rgb + vec3(0.4), 0.0, 1.0);
    vec3 highlight = dotColor * finalMask * 2.5;

    // Combine soft background and animated fat dots
    vec3 finalColor = softLight + highlight;

    return vec4(finalColor, baseColor.a);
}

