// NAME: Psychedelic Snake
uniform float scale; // @min 1.0 @max 50.0 @default 10.0
uniform float speed; // @min 0.0 @max 5.0 @default 0.5
uniform float dash_freq; // @min 1.0 @max 20.0 @default 8.0
uniform float thickness; // @min 0.01 @max 0.5 @default 0.15
uniform float blur; // @min 0.0 @max 0.2 @default 0.05
uniform float dark_threshold; // @min 0.0 @max 1.0 @default 0.1
uniform float warp_strength; // @min -0.5 @max 0.5 @default 0.1
uniform float chrome_mix; // @min 0.0 @max 1.0 @default 0.85
uniform float ripple_strength; // @min 0.0 @max 0.2 @default 0.05

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    // Ripple distortion
    vec2 aspect = vec2(resolution.x / resolution.y, 1.0);
    vec2 dir = (uv - 0.5) * aspect;
    float dist = length(dir);
    float ripple = exp(-30.0 * abs(dist - (1.0 - fract(time)))) * sin((dist - (1.0 - fract(time))) * 40.0);
    vec2 uvW = uv + (dist > 0.001 ? (dir / dist) : vec2(0.0)) * ripple * ripple_strength / aspect;

    vec4 src = texture2D(tex, uvW);
    if (length(src.rgb) < dark_threshold || src.a < 0.01) return vec4(0.0);

    // Compact RGB to HSV for color isolation
    vec3 c = src.rgb;
    vec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);
    vec4 p = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));
    vec4 q = mix(vec4(p.xyw, c.r), vec4(c.r, p.yzx), step(p.x, c.r));
    float d_hsv = q.x - min(q.w, q.y);
    vec3 hsv = vec3(abs(q.z + (q.w - q.y) / (6.0 * d_hsv + 1e-10)), d_hsv / (q.x + 1e-10), q.x);

    // Isolate Violet to Green range
    if (!((hsv.x > 0.70 || hsv.x < 0.35) && hsv.y > 0.2 && hsv.z > 0.2)) return vec4(0.0);

    // Psychedelic Snake Tiling
    vec2 st = abs(uvW - 0.5) * (scale + sin(time * 0.5) * 3.0);
    vec2 ip = floor(st);
    vec2 fp = fract(st);
    if (node_rand(ip) > 0.5) fp.x = 1.0 - fp.x;

    float d1 = length(fp), d2 = length(fp - 1.0);
    float d = min(abs(d1 - 0.5), abs(d2 - 0.5));
    float dyn_thick = thickness + sin(time * 1.2) * 0.05;
    float mask = smoothstep(dyn_thick, dyn_thick - blur, d);
    mask *= step(0.5, fract((min(d1, d2) - time * speed) * (dash_freq + cos(time * 0.8) * 4.0)));

    if (mask < 0.01) return vec4(0.0);

    // Chrome and Warp effect
    vec2 finalUV = uvW + (uvW - 0.5) * mask * warp_strength;
    vec4 warpedSrc = texture2D(tex, finalUV);
    float chrome = max(dot(vec3(d / dyn_thick, sqrt(max(0.0, 1.0 - pow(d/dyn_thick, 2.0))), 0.0), vec3(0.707)), 0.0);

    return vec4(mix(warpedSrc.rgb, vec3(chrome) * hsv.z, chrome_mix), src.a * mask);
}

