float gear(vec2 p, float radius)
{
    //length of cog
    float sp = floor(radius*PI2)*2.;
    float gs = length(p.xy)-radius;
    float at = atan(p.y,p.x);
    //gear teeth
    float gw = abs(sin(at*sp)*.15);
    gs +=smoothstep(.05,.5,gw);

    gs=max(gs, -(length(p.xy)-(radius*.45)) );
    return gs;
}

