    vec2 st = abs(uvW - 0.5) * (scale + sin(time * 0.5) * 3.0);
    vec2 ip = floor(st);
    vec2 fp = fract(st);
    if (node_rand(ip) > 0.5) fp.x = 1.0 - fp.x;

