// NAME: HD 3D Dual Relight
uniform float lightHeight; // @min 0.01 @max 1.0 @default 0.15
uniform float lightIntensity; // @min 0.0 @max 5.0 @default 2.5
uniform float ambient; // @min 0.0 @max 1.0 @default 0.15
uniform float shininess; // @min 1.0 @max 100.0 @default 40.0
uniform float detail; // @min 0.1 @max 10.0 @default 3.0
uniform vec3 lightColor1; // @default 0.0,0.8,1.0
uniform vec3 lightColor2; // @default 1.0,0.2,0.5

float getLuma(vec4 c) {
    return dot(c.rgb, vec3(0.299, 0.587, 0.114));
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 texel = 1.0 / resolution;

    // Sample base color
    vec4 base = texture2D(tex, uv);

    // Mask to prevent any lighting on black or near-black pixels
    float isNotBlack = step(0.01, max(max(base.r, base.g), base.b));

    // High Definition Normal Generation using Sobel Operator
    float tl = getLuma(texture2D(tex, uv + vec2(-texel.x, -texel.y)));
    float tc = getLuma(texture2D(tex, uv + vec2(0.0, -texel.y)));
    float tr = getLuma(texture2D(tex, uv + vec2(texel.x, -texel.y)));
    float ml = getLuma(texture2D(tex, uv + vec2(-texel.x, 0.0)));
    float mr = getLuma(texture2D(tex, uv + vec2(texel.x, 0.0)));
    float bl = getLuma(texture2D(tex, uv + vec2(-texel.x, texel.y)));
    float bc = getLuma(texture2D(tex, uv + vec2(0.0, texel.y)));
    float br = getLuma(texture2D(tex, uv + vec2(texel.x, texel.y)));

    float dX = (tr + 2.0 * mr + br) - (tl + 2.0 * ml + bl);
    float dY = (bl + 2.0 * bc + br) - (tl + 2.0 * tc + tr);

    // Construct high-detail normal vector
    vec3 normal = normalize(vec3(dX * detail, dY * detail, 0.1));

    // Current pixel position in 3D space
    vec3 fragPos = vec3(uv, 0.0);
    vec3 viewDir = vec3(0.0, 0.0, 1.0);

    // Moving light positions
    vec3 lightPos1 = vec3(0.5 + 0.4 * sin(time), 0.5 + 0.4 * cos(time * 1.3), lightHeight);
    vec3 lightPos2 = vec3(0.5 + 0.4 * cos(time * 1.1), 0.5 + 0.4 * sin(time * 0.8), lightHeight);

    // Calculate Light 1
    vec3 L1 = normalize(lightPos1 - fragPos);
    vec3 H1 = normalize(L1 + viewDir);
    float diff1 = max(dot(normal, L1), 0.0);
    float spec1 = pow(max(dot(normal, H1), 0.0), shininess);
    vec3 dist1 = lightPos1 - fragPos;
    float att1 = 1.0 / (1.0 + 10.0 * dot(dist1, dist1));

    // Calculate Light 2
    vec3 L2 = normalize(lightPos2 - fragPos);
    vec3 H2 = normalize(L2 + viewDir);
    float diff2 = max(dot(normal, L2), 0.0);
    float spec2 = pow(max(dot(normal, H2), 0.0), shininess);
    vec3 dist2 = lightPos2 - fragPos;
    float att2 = 1.0 / (1.0 + 10.0 * dot(dist2, dist2));

    // Combine lighting components
    vec3 ambientLight = base.rgb * ambient;
    vec3 diffuseLight = base.rgb * (diff1 * lightColor1 * att1 + diff2 * lightColor2 * att2) * lightIntensity;
    vec3 specularLight = (spec1 * lightColor1 * att1 + spec2 * lightColor2 * att2) * lightIntensity;

    // Apply the mask to the final color to ensure black pixels stay completely dark
    vec3 finalColor = (ambientLight + diffuseLight + specularLight) * isNotBlack;

    return vec4(clamp(finalColor, 0.0, 1.0), base.a);
}

