    vec3 L2 = l2 * inversesqrt(distSq2);

    vec3 H1 = normalize(L1 + viewDir);
    vec3 H2 = normalize(L2 + viewDir);

    float diff1 = max(dot(normal, L1), 0.0);
    float diff2 = max(dot(normal, L2), 0.0);
    float spec1 = pow(max(dot(normal, H1), 0.0), shininess);
    float spec2 = pow(max(dot(normal, H2), 0.0), shininess);

    float att1 = 1.0 / (1.0 + 10.0 * distSq1);
    float att2 = 1.0 / (1.0 + 10.0 * distSq2);

