    vec3 diffuseLight = base.rgb * (diff1 * animColor1 * att1 + diff2 * animColor2 * att2) * lightIntensity;
    vec3 specularLight = (spec1 * animColor1 * att1 + spec2 * animColor2 * att2) * lightIntensity;

    vec3 finalColor = (ambientLight + diffuseLight + specularLight) * isNotBlack;

    return vec4(clamp(finalColor, 0.0, 1.0), base.a);
