    vec2 lightPosAspect = lightPos;
    lightPosAspect.x *= resolution.x / resolution.y;

    float lDist = distance(lightUv, lightPosAspect);

    // Illuminate the mix without showing the light source itself
    float illumination = smoothstep(0.6, 0.0, lDist);
    vec3 lightColor = vec3(1.0, 0.9, 0.7);

    // Multiply the existing color by the illumination factor
    finalColor *= 1.0 + (lightColor * illumination * 2.5);

    return vec4(finalColor, baseColor.a);
}

