                       smoothstep(0.0, 0.15, uv.y) * smoothstep(1.0, 0.85, uv.y);

    float sizeMask = smoothstep(spiralSize, 0.05, r) * borderMask;
    float spot = smoothstep(0.5, 1.5, mathBlob) * sizeMask;
    float lsdEdge = smoothstep(lsdGlowWidth, 0.0, abs(mathBlob - 0.3)) * sizeMask;

    vec3 lsdColor = lineColor1;

    finalColor += lsdColor * lsdEdge * blackSpotAmount * 2.0;
    finalColor = mix(finalColor, vec3(0.0), spot * blackSpotAmount);

    vec2 lightPos = vec2(
        0.5 + 0.4 * sin(time * 1.1 + node_noise(vec2(time * 0.5, 0.0))),
        0.5 + 0.4 * cos(time * 1.3 + node_noise(vec2(0.0, time * 0.5)))
    );

    vec2 lightPos2 = vec2(
        0.5 + 0.3 * cos(time * 2.3 + node_noise(vec2(time, 0.0))),
        0.5 + 0.3 * sin(time * 1.9 + node_noise(vec2(0.0, time)))
    );

    vec2 lightUv = uv;
    lightUv.x *= resolution.x / resolution.y;

    vec2 lightPosAspect = lightPos;
    lightPosAspect.x *= resolution.x / resolution.y;

    vec2 lightPosAspect2 = lightPos2;
    lightPosAspect2.x *= resolution.x / resolution.y;

    float lDist = distance(lightUv, lightPosAspect);
    float lDist2 = distance(lightUv, lightPosAspect2);

    // Smoother gradient for the main light
    float illumination = pow(smoothstep(1.2, 0.0, lDist), 1.5);
    vec3 lightColor = vec3(1.0, 0.9, 0.7);

    finalColor *= illumination * (1.0 + lightColor * 2.5);

    if (blackLinesInLight) {
        float totalLines = clamp((edge * segment1 * 2.0) + (edge * segment2 * 1.5) + (lsdEdge * 2.0), 0.0, 1.0);
        finalColor = mix(finalColor, vec3(0.0), totalLines * illumination);
    }

    // Second light: low on the ground, invisible source, illuminates the surface
    float illumination2 = pow(smoothstep(0.8, 0.0, lDist2), 2.0);
    finalColor *= 1.0 + (illumination2 * secondLightColor * 2.0);

    return vec4(finalColor, baseColor.a);
}

// NAME: 3D Dual Light Spiral Inverted Ground
uniform float speed; // @min -10.0 @max 10.0 @default 5.0
uniform float speed2; // @min -10.0 @max 10.0 @default 3.0
uniform float lineLength; // @min 1.0 @max 10.0 @default 1.0
uniform float delay; // @min 0.0 @max 5.0 @default 2.0
uniform float distOffset; // @min 0.0 @max 20.0 @default 10.0
uniform float centerBlur; // @min 0.0 @max 0.5 @default 0.1
uniform vec3 waveColor1; // @default 1.0,0.2,0.5
uniform vec3 waveColor2; // @default 0.2,0.8,1.0
uniform vec3 waveColor3; // @default 0.5,1.0,0.2
uniform float waveFreq; // @min 1.0 @max 50.0 @default 20.0
uniform float blackSpotAmount; // @min 0.0 @max 1.0 @default 0.8
uniform float spiralScale; // @min 5.0 @max 100.0 @default 40.0
uniform float spiralSpeed; // @min -20.0 @max 20.0 @default 7.0
uniform float spiralSize; // @min 0.05 @max 1.0 @default 0.3
uniform float lsdGlowWidth; // @min 0.1 @max 2.0 @default 0.8
uniform float prime1; // @min 1.0 @max 13.0 @default 2.0
uniform float prime2; // @min 1.0 @max 13.0 @default 3.0
uniform bool blackLinesInLight; // @default false
uniform vec3 secondLightColor; // @default 0.8,0.9,1.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 baseColor = texture2D(tex, uv);

    vec2 symUv = uv;
    float dir = 1.0;
    if (symUv.x > 0.5) {
        symUv.x = 1.0 - symUv.x;
        dir = -1.0;
    }

    float blob = node_noise(symUv * 5.0);
    float localTime = time;
    if (blob > 0.0) {
        localTime = time - delay;
    }

    vec2 off = 1.0 / resolution;

    float t00 = texture2D(tex, uv + vec2(-off.x, -off.y)).r;
    float t10 = texture2D(tex, uv + vec2( 0.0,   -off.y)).r;
    float t20 = texture2D(tex, uv + vec2( off.x, -off.y)).r;
    float t01 = texture2D(tex, uv + vec2(-off.x,  0.0)).r;
    float t21 = texture2D(tex, uv + vec2( off.x,  0.0)).r;
    float t02 = texture2D(tex, uv + vec2(-off.x,  off.y)).r;
    float t12 = texture2D(tex, uv + vec2( 0.0,    off.y)).r;
    float t22 = texture2D(tex, uv + vec2( off.x,  off.y)).r;

    float gx = (t00 + 2.0 * t01 + t02) - (t20 + 2.0 * t21 + t22);
    float gy = (t00 + 2.0 * t10 + t20) - (t02 + 2.0 * t12 + t22);

    float edge = sqrt(gx * gx + gy * gy);
    float angle = atan(gy, gx);

    float dist = distance(uv, vec2(0.5));

    float segment1 = sin(angle * lineLength + localTime * speed * dir - dist * distOffset);
    float segment2 = sin(angle * lineLength - localTime * speed2 * dir - dist * distOffset * 0.7);

    float centerDist = abs(uv.x - 0.5);
    float blurFactor = smoothstep(centerBlur + 0.001, 0.0, centerDist);

    float edgeMin = mix(0.7, 0.0, blurFactor);
    float edgeMax = mix(0.95, 1.0, blurFactor);
    segment1 = smoothstep(edgeMin, edgeMax, segment1);
    segment2 = smoothstep(0.2, 0.8, segment2);

    vec3 softLight = baseColor.rgb * 0.4;

    float wave1 = sin(dist * waveFreq - time * speed) * 0.5 + 0.5;
    vec3 lineColor1 = mix(waveColor1, waveColor2, wave1);

    float wave2 = sin(dist * waveFreq * 0.6 + time * speed2) * 0.5 + 0.5;
    vec3 lineColor2 = mix(waveColor2, waveColor3, wave2);

    vec3 highlight1 = lineColor1 * edge * segment1 * 2.0;
    vec3 highlight2 = lineColor2 * edge * segment2 * 1.5;

    vec3 finalColor = softLight + highlight1 + highlight2;

    vec2 centeredUv = symUv - vec2(0.5);
    centeredUv.x *= resolution.x / resolution.y;

    float r = length(centeredUv);
    float a = atan(centeredUv.y, centeredUv.x);

    float p1 = prime1;
    float p2 = prime2;
    float p3 = 5.0;
    float p5 = 11.0;

    float scaledR = r * spiralScale;
    float spiral = a * p3 + scaledR * p1 - time * spiralSpeed;
    float mathBlob = sin(spiral) + cos(scaledR * p2 + a * p5) + sin(scaledR * p1 - time * p3);

    float borderMask = smoothstep(0.0, 0.15, uv.x) * smoothstep(1.0, 0.85, uv.x) * 
                       smoothstep(0.0, 0.15, uv.y) * smoothstep(1.0, 0.85, uv.y);

    float sizeMask = smoothstep(spiralSize, 0.05, r) * borderMask;
    float spot = smoothstep(0.5, 1.5, mathBlob) * sizeMask;
    float lsdEdge = smoothstep(lsdGlowWidth, 0.0, abs(mathBlob - 0.3)) * sizeMask;

    vec3 lsdColor = lineColor1;

    finalColor += lsdColor * lsdEdge * blackSpotAmount * 2.0;
    finalColor = mix(finalColor, vec3(0.0), spot * blackSpotAmount);

    vec2 lightPos = vec2(
        0.5 + 0.4 * sin(time * 1.1 + node_noise(vec2(time * 0.5, 0.0))),
        0.5 + 0.4 * cos(time * 1.3 + node_noise(vec2(0.0, time * 0.5)))
    );

    // Random movement different from the first light
    vec2 lightPos2 = vec2(
        0.5 + 0.4 * sin(time * 0.85 + node_noise(vec2(time * 0.2, 5.0)) * 10.0),
        0.5 + 0.4 * cos(time * 0.65 + node_noise(vec2(5.0, time * 0.2)) * 10.0)
    );

    vec2 lightUv = uv;
    lightUv.x *= resolution.x / resolution.y;

    vec2 lightPosAspect = lightPos;
    lightPosAspect.x *= resolution.x / resolution.y;

    vec2 lightPosAspect2 = lightPos2;
    lightPosAspect2.x *= resolution.x / resolution.y;

    float lDist = distance(lightUv, lightPosAspect);
    float lDist2 = distance(lightUv, lightPosAspect2);

    // Main light
    float illumination = pow(smoothstep(1.2, 0.0, lDist), 1.5);
    vec3 lightColor = vec3(1.0, 0.9, 0.7);

    finalColor *= illumination * (1.0 + lightColor * 2.5);

    if (blackLinesInLight) {
        float totalLines = clamp((edge * segment1 * 2.0) + (edge * segment2 * 1.5) + (lsdEdge * 2.0), 0.0, 1.0);
        finalColor = mix(finalColor, vec3(0.0), totalLines * illumination);
    }

    // Second light: low on the ground, invisible source, illuminates the surface with inverted colors
    float illumination2 = pow(smoothstep(0.8, 0.0, lDist2), 2.0);
    vec3 invertedBase = vec3(1.0) - baseColor.rgb;
    vec3 invertedLit = invertedBase * secondLightColor * 2.5;

    finalColor = mix(finalColor, invertedLit, illumination2);

    return vec4(finalColor, baseColor.a);
}

