    float segment2 = sin(angle * lineLength - localTime * speed2 * dir - dist * distOffset * 0.7);

    float centerDist = abs(uv.x - 0.5);
    float blurFactor = smoothstep(centerBlur + 0.001, 0.0, centerDist);

    float edgeMin = mix(0.7, 0.0, blurFactor);
    float edgeMax = mix(0.95, 1.0, blurFactor);
    segment1 = smoothstep(edgeMin, edgeMax, segment1);
    segment2 = smoothstep(0.2, 0.8, segment2);

    vec3 softLight = baseColor.rgb * 0.4;

    float wave1 = sin(dist * waveFreq - time * speed) * 0.5 + 0.5;
    vec3 lineColor1 = mix(waveColor1, waveColor2, wave1);

    float wave2 = sin(dist * waveFreq * 0.6 + time * speed2) * 0.5 + 0.5;
    vec3 lineColor2 = mix(waveColor2, waveColor3, wave2);

    vec3 highlight1 = lineColor1 * edge * segment1 * 2.0;
    vec3 highlight2 = lineColor2 * edge * segment2 * 1.5;

