    vec3 eyeBaseColor = baseColor.rgb * 2.0; 
    vec3 eyePupilColor = vec3(0.05); // Dark pupil

    vec3 eyeRender = mix(eyeBaseColor, eyePupilColor, pupilMask);

    // Calculate total illumination from both lights
    float totalIllum = clamp(illumination + illumination2, 0.0, 1.0);

    // Eye light glow masked by illumination
