    finalColor += eyeBaseColor * 0.5 * eyeGlow;

    // Composite eye over the scene, only visible when illuminated
    finalColor = mix(finalColor, eyeRender, eyeMask * totalIllum);

    return vec4(finalColor, baseColor.a);
}

