vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 baseColor = texture2D(tex, uv);
    vec2 symUv = uv;
    if (symUv.x > 0.5) symUv.x = 1.0 - symUv.x;

    vec2 off = 1.0 / resolution;
    float t00 = texture2D(tex, uv + vec2(-off.x, -off.y)).r;
    float t22 = texture2D(tex, uv + vec2( off.x,  off.y)).r;
    float edge = abs(t00 - t22) * 5.0;

    float dist = distance(uv, vec2(0.5));
    float wave = sin(dist * waveFreq - time * speed) * 0.5 + 0.5;
    vec3 lineColor = mix(waveColor1, waveColor2, wave);

    vec3 finalColor = baseColor.rgb * 0.4 + lineColor * edge;

    // 3D Fisheye Sphere Eye
    vec2 eyePos = vec2(0.5 + 0.3 * sin(time), 0.5 + 0.2 * cos(time * 1.3));
    vec2 lightUv = uv;
    lightUv.x *= resolution.x / resolution.y;
    vec2 eyePosAspect = eyePos;
    eyePosAspect.x *= resolution.x / resolution.y;

    vec2 eyeDelta = lightUv - eyePosAspect;
    float sphereRadius = 0.25;
    float eyeDistRaw = length(eyeDelta);

    float sphereMask = smoothstep(sphereRadius, sphereRadius - 0.01, eyeDistRaw);
    float z = sqrt(max(0.0, sphereRadius * sphereRadius - eyeDistRaw * eyeDistRaw));
    vec3 normal = normalize(vec3(eyeDelta, z));

    vec2 sphereUv = normal.xy * 0.5 + 0.5;
    float irisMask = smoothstep(0.35, 0.32, length(sphereUv - vec2(0.5)));
    float pupilMask = smoothstep(0.12, 0.09, length(sphereUv - vec2(0.5)));

    vec2 distortedBaseUv = uv + normal.xy * 0.15;
    vec3 eyeBaseColor = texture2D(tex, distortedBaseUv).rgb * 2.0; 
    vec3 scleraColor = vec3(0.9, 0.8, 0.8);

    vec3 eyeColor = mix(scleraColor, eyeBaseColor, irisMask);
    eyeColor = mix(eyeColor, vec3(0.05), pupilMask);

    float spec = pow(max(dot(normal, normalize(vec3(0.5, 0.5, 1.0))), 0.0), 30.0);
    eyeColor += spec;

    finalColor = mix(finalColor, eyeColor, sphereMask);

    return vec4(finalColor, baseColor.a);
}

