// NAME: 3D Dual Light Spiral
uniform float speed; // @min -10.0 @max 10.0 @default 5.0
uniform float spiralScale; // @min 5.0 @max 100.0 @default 40.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 baseColor = texture2D(tex, uv);
    vec2 off = 1.0 / resolution;

    // Edge detection for normal mapping
    float t00 = texture2D(tex, uv + vec2(-off.x, -off.y)).r;
    float t10 = texture2D(tex, uv + vec2( 0.0,   -off.y)).r;
    float t20 = texture2D(tex, uv + vec2( off.x, -off.y)).r;
    float t01 = texture2D(tex, uv + vec2(-off.x,  0.0)).r;
    float t21 = texture2D(tex, uv + vec2( off.x,  0.0)).r;
    float t02 = texture2D(tex, uv + vec2(-off.x,  off.y)).r;
    float t12 = texture2D(tex, uv + vec2( 0.0,    off.y)).r;
    float t22 = texture2D(tex, uv + vec2( off.x,  off.y)).r;

    float gx = (t00 + 2.0 * t01 + t02) - (t20 + 2.0 * t21 + t22);
    float gy = (t00 + 2.0 * t10 + t20) - (t02 + 2.0 * t12 + t22);
    vec3 normal = normalize(vec3(gx, gy, 0.5));

    // Mask to prevent lights from illuminating dark background pixels
    float baseLuma = dot(baseColor.rgb, vec3(0.299, 0.587, 0.114));
    float colorMask = smoothstep(0.05, 0.2, baseLuma);

    // Dynamic light positions
    vec2 lightPos1 = vec2(0.5 + 0.4 * sin(time), 0.5 + 0.4 * cos(time * 1.3));
    vec2 lightPos2 = vec2(0.5 + 0.4 * cos(time * 0.8), 0.5 + 0.4 * sin(time * 1.1));

    vec2 aspectUv = uv;
    aspectUv.x *= resolution.x / resolution.y;
    lightPos1.x *= resolution.x / resolution.y;
    lightPos2.x *= resolution.x / resolution.y;

    vec3 lightDir1 = normalize(vec3(lightPos1 - aspectUv, 0.3));
    vec3 lightDir2 = normalize(vec3(lightPos2 - aspectUv, 0.3));

    // Diffuse lighting
    float diff1 = max(dot(normal, lightDir1), 0.0);
    float diff2 = max(dot(normal, lightDir2), 0.0);

    float dist1 = distance(aspectUv, lightPos1);
    float dist2 = distance(aspectUv, lightPos2);

    float atten1 = smoothstep(1.0, 0.0, dist1);
    float atten2 = smoothstep(1.0, 0.0, dist2);

    vec3 lightColor1 = vec3(1.0, 0.4, 0.2) * diff1 * atten1 * 1.5;
    vec3 lightColor2 = vec3(0.2, 0.5, 1.0) * diff2 * atten2 * 1.5;

    // Apply color mask to lights
    vec3 totalLight = (lightColor1 + lightColor2) * colorMask;

    // Spiral effect
    vec2 centered = uv - 0.5;
    float r = length(centered);
    float a = atan(centered.y, centered.x);
    float spiral = sin(a * 5.0 + r * spiralScale - time * speed);

    vec3 finalColor = baseColor.rgb * 0.4 + totalLight + (spiral * 0.15 * colorMask * vec3(0.8, 0.9, 1.0));

    return vec4(finalColor, baseColor.a);
}

// NAME: 3D Dual Light Spiral
uniform float speed; // @min -10.0 @max 10.0 @default 5.0
uniform float waveFreq; // @min 1.0 @max 50.0 @default 20.0
uniform vec3 waveColor1; // @default 1.0,0.2,0.5
uniform vec3 waveColor2; // @default 0.2,0.8,1.0
uniform vec3 secondLightColor; // @default 0.8,0.9,1.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 baseColor = texture2D(tex, uv);
    vec2 off = 1.0 / resolution;

    float t00 = texture2D(tex, uv + vec2(-off.x, -off.y)).r;
    float t10 = texture2D(tex, uv + vec2( 0.0,   -off.y)).r;
    float t20 = texture2D(tex, uv + vec2( off.x, -off.y)).r;
    float t01 = texture2D(tex, uv + vec2(-off.x,  0.0)).r;
    float t21 = texture2D(tex, uv + vec2( off.x,  0.0)).r;
    float t02 = texture2D(tex, uv + vec2(-off.x,  off.y)).r;
    float t12 = texture2D(tex, uv + vec2( 0.0,    off.y)).r;
    float t22 = texture2D(tex, uv + vec2( off.x,  off.y)).r;

    float gx = (t00 + 2.0 * t01 + t02) - (t20 + 2.0 * t21 + t22);
    float gy = (t00 + 2.0 * t10 + t20) - (t02 + 2.0 * t12 + t22);
    float edge = sqrt(gx * gx + gy * gy);

    vec2 centeredUv = uv - 0.5;
    centeredUv.x *= resolution.x / resolution.y;
    float r = length(centeredUv);
    float a = atan(centeredUv.y, centeredUv.x);

    float spiral = sin(a * 5.0 + r * 20.0 - time * speed);
    float mask = smoothstep(0.2, 0.8, spiral);

    vec3 color1 = mix(waveColor1, waveColor2, sin(r * waveFreq - time) * 0.5 + 0.5);
    vec3 highlight = color1 * edge * mask * 2.0;

    vec2 lightPos1 = vec2(0.5 + 0.3 * sin(time), 0.5 + 0.3 * cos(time));
    vec2 lightPos2 = vec2(0.5 + 0.3 * sin(time * 1.3 + 2.0), 0.5 + 0.3 * cos(time * 1.3 + 2.0));

    float lDist1 = distance(uv, lightPos1);
    float lDist2 = distance(uv, lightPos2);

    float ill1 = pow(smoothstep(0.6, 0.0, lDist1), 2.0);
    float ill2 = pow(smoothstep(0.6, 0.0, lDist2), 2.0);

    vec3 finalColor = baseColor.rgb * 0.4 + highlight;
    finalColor += ill1 * color1 * 0.5 + ill2 * secondLightColor * 0.5;

    return vec4(finalColor, baseColor.a);
}

// NAME: Frenetic Dual Light Spiral
uniform float speed; // @min -10.0 @max 10.0 @default 5.0
uniform float speed2; // @min -20.0 @max 20.0 @default 15.0
uniform float waveFreq; // @min 1.0 @max 50.0 @default 20.0
uniform vec3 waveColor1; // @default 1.0,0.2,0.5

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 baseColor = texture2D(tex, uv);
    vec2 off = 1.0 / resolution;

    // Simple edge detection
    float t00 = texture2D(tex, uv + vec2(-off.x, -off.y)).r;
    float t20 = texture2D(tex, uv + vec2( off.x, -off.y)).r;
    float t02 = texture2D(tex, uv + vec2(-off.x,  off.y)).r;
    float t22 = texture2D(tex, uv + vec2( off.x,  off.y)).r;
    float gx = t00 - t22;
    float gy = t20 - t02;
    float edge = sqrt(gx * gx + gy * gy) * 2.5;

    vec2 centeredUv = uv - 0.5;
    centeredUv.x *= resolution.x / resolution.y;
    float r = length(centeredUv);
    float a = atan(centeredUv.y, centeredUv.x);

    // Line 1 (Standard)
    float segment1 = smoothstep(0.2, 0.8, sin(a * 3.0 + r * 12.0 - time * speed));
    vec3 color1 = mix(waveColor1, vec3(0.2, 0.8, 1.0), sin(r * waveFreq - time) * 0.5 + 0.5);

    // Line 2 (Frenetic & looping intensity)
    float segment2 = smoothstep(0.1, 0.9, sin(a * 12.0 - r * 25.0 + time * speed2));
    float intensity2 = 0.5 + 0.5 * sin(time * 12.0); // Fast pulsing intensity

    // Random looping colors using noise
    vec3 randLineColor = vec3(
        node_noise(vec2(time * 0.8, 0.0)), 
        node_noise(vec2(0.0, time * 0.9)), 
        node_noise(vec2(time * 0.7, 1.0))
    );

    vec3 randLightColor = vec3(
        node_noise(vec2(time * 0.5, 2.0)), 
        node_noise(vec2(3.0, time * 0.6)), 
        node_noise(vec2(time * 0.4, 4.0))
    );

    vec3 highlight1 = color1 * edge * segment1 * 2.0;
    vec3 highlight2 = randLineColor * edge * segment2 * 4.0 * intensity2;

    // Lights
    vec2 lightPos1 = vec2(0.5 + 0.3 * sin(time), 0.5 + 0.3 * cos(time));
    vec2 lightPos2 = vec2(0.5 + 0.4 * sin(time * 3.1), 0.5 + 0.4 * cos(time * 2.7));

    float lDist1 = distance(uv, lightPos1);
    float lDist2 = distance(uv, lightPos2);

    float ill1 = pow(smoothstep(0.8, 0.0, lDist1), 2.0);
    float ill2 = pow(smoothstep(0.8, 0.0, lDist2), 2.0);

    vec3 finalColor = baseColor.rgb * 0.3 + highlight1 + highlight2;
    finalColor += ill1 * color1 * 0.8 + ill2 * randLightColor * 2.0;

    return vec4(finalColor, baseColor.a);
}

// NAME: 3D Dual Light Spiral Masked Ground
uniform float speed; // @min -10.0 @max 10.0 @default 5.0
uniform float speed2; // @min -10.0 @max 10.0 @default 3.0
uniform float lineLength; // @min 1.0 @max 10.0 @default 1.0
uniform float delay; // @min 0.0 @max 5.0 @default 2.0
uniform float distOffset; // @min 0.0 @max 20.0 @default 10.0
uniform float centerBlur; // @min 0.0 @max 0.5 @default 0.1
uniform vec3 waveColor1; // @default 1.0,0.2,0.5
uniform vec3 waveColor2; // @default 0.2,0.8,1.0
uniform vec3 waveColor3; // @default 0.5,1.0,0.2
uniform float waveFreq; // @min 1.0 @max 50.0 @default 20.0
uniform float blackSpotAmount; // @min 0.0 @max 1.0 @default 0.8
uniform float spiralScale; // @min 5.0 @max 100.0 @default 40.0
uniform float spiralSpeed; // @min -20.0 @max 20.0 @default 7.0
uniform float spiralSize; // @min 0.05 @max 1.0 @default 0.3
uniform float lsdGlowWidth; // @min 0.1 @max 2.0 @default 0.8
uniform float prime1; // @min 1.0 @max 13.0 @default 2.0
uniform float prime2; // @min 1.0 @max 13.0 @default 3.0
uniform bool blackLinesInLight; // @default false
uniform vec3 secondLightColor; // @default 0.8,0.9,1.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 baseColor = texture2D(tex, uv);

    vec2 symUv = uv;
    float dir = 1.0;
    if (symUv.x > 0.5) {
        symUv.x = 1.0 - symUv.x;
        dir = -1.0;
    }

    float blob = node_noise(symUv * 5.0);
    float localTime = time;
    if (blob > 0.0) {
        localTime = time - delay;
    }

