    float segment1 = sin(angle * lineLength + localTime * speed * dir - dist * distOffset);
    float segment2 = sin(angle * lineLength - localTime * speed2 * dir - dist * distOffset * 0.7);

    float centerDist = abs(uv.x - 0.5);
    float blurFactor = smoothstep(centerBlur + 0.001, 0.0, centerDist);

    float edgeMin = mix(0.7, 0.0, blurFactor);
    float edgeMax = mix(0.95, 1.0, blurFactor);
    segment1 = smoothstep(edgeMin, edgeMax, segment1);
    segment2 = smoothstep(0.2, 0.8, segment2);

    vec3 softLight = baseColor.rgb * 0.4;

    float loopTime1 = fract(time * speed * 0.05);
    vec2 loopDir1 = vec2(cos(loopTime1 * 6.2831853), sin(loopTime1 * 6.2831853));
    float wave1 = node_noise(vec2(dist * waveFreq, 0.0) + loopDir1) * 0.5 + 0.5;
    vec3 lineColor1 = mix(waveColor1, waveColor2, wave1);

    float loopTime2 = fract(time * speed2 * 0.05);
    vec2 loopDir2 = vec2(cos(loopTime2 * 6.2831853), sin(loopTime2 * 6.2831853));
    float wave2 = node_noise(vec2(dist * waveFreq * 0.6, 5.0) + loopDir2) * 0.5 + 0.5;
    vec3 lineColor2 = mix(waveColor2, waveColor3, wave2);

    vec3 highlight1 = lineColor1 * edge * segment1 * 2.0;
    vec3 highlight2 = lineColor2 * edge * segment2 * 1.5;

    vec3 finalColor = softLight + highlight1 + highlight2;

    vec2 centeredUv = symUv - vec2(0.5);
    centeredUv.x *= resolution.x / resolution.y;

    float r = length(centeredUv);
    float a = atan(centeredUv.y, centeredUv.x);

    float p1 = prime1;
    float p2 = prime2;
    float p3 = 5.0;
    float p5 = 11.0;

    float scaledR = r * spiralScale;
    float spiral = a * p3 + scaledR * p1 - time * spiralSpeed;
    float mathBlob = sin(spiral) + cos(scaledR * p2 + a * p5) + sin(scaledR * p1 - time * p3);

    float borderMask = smoothstep(0.0, 0.15, uv.x) * smoothstep(1.0, 0.85, uv.x) * 
                       smoothstep(0.0, 0.15, uv.y) * smoothstep(1.0, 0.85, uv.y);

    float sizeMask = smoothstep(spiralSize, 0.05, r) * borderMask;
    float spot = smoothstep(0.5, 1.5, mathBlob) * sizeMask;
    float lsdEdge = smoothstep(lsdGlowWidth, 0.0, abs(mathBlob - 0.3)) * sizeMask;

    vec3 lsdColor = lineColor1;

    finalColor += lsdColor * lsdEdge * blackSpotAmount * 2.0;
    finalColor = mix(finalColor, vec3(0.0), spot * blackSpotAmount);

    vec2 lightPos = vec2(
        0.5 + 0.4 * sin(time * 1.1 + node_noise(vec2(time * 0.5, 0.0))),
        0.5 + 0.4 * cos(time * 1.3 + node_noise(vec2(0.0, time * 0.5)))
    );

    vec2 lightPos2 = vec2(
