    vec3 dynWave2 = vec3(cos(time * 0.5), sin(time * 0.6), cos(time * 0.4)) * 0.5 + 0.5;
    vec3 dynWave3 = vec3(sin(time * 0.7), cos(time * 0.8), sin(time * 0.6)) * 0.5 + 0.5;

