vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 baseColor = texture2D(tex, uv);
    float luma = dot(baseColor.rgb, vec3(0.299, 0.587, 0.114));
    float effectMask = smoothstep(0.01, 0.1, luma);

    vec2 symUv = uv;
    float dir = (symUv.x > 0.5) ? -1.0 : 1.0;
    if (symUv.x > 0.5) symUv.x = 1.0 - symUv.x;

    float localTime = (node_noise(symUv * 5.0) > 0.0) ? time - delay : time;
    vec2 off = 1.0 / resolution;
