    float wave2 = sin(dist * waveFreq * 0.6 + time * speed2) * 0.5 + 0.5;
    vec3 lineColor2 = mix(dynWave2, dynWave3, wave2);

    vec3 highlight1 = lineColor1 * edge * segment1 * 2.0;
    vec3 highlight2 = lineColor2 * edge * segment2 * 1.5;

