    }

    float luma = dot(baseColor.rgb, vec3(0.299, 0.587, 0.114));
    float nonBlackMask = smoothstep(0.05, 0.2, luma);

    // Hard shadow logic: sharp cutoff for the light radius and sharp blocking by edges
    float hardShadow = smoothstep(0.1, 0.05, edge);
