// NAME: 3D Sculpture Spotlight
uniform float light_height; // @min 0.05 @max 1.0 @default 0.3
uniform float light_size; // @min 0.1 @max 2.0 @default 0.8
uniform float bump_strength; // @min 0.001 @max 0.1 @default 0.03
uniform float shininess; // @min 1.0 @max 64.0 @default 32.0
uniform vec3 light_color; // @default 1.0,1.0,0.9

float getLuma(vec3 rgb) {
    return dot(rgb, vec3(0.299, 0.587, 0.114));
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 texel = 1.0 / resolution;
    vec4 source = texture2D(tex, uv);

    // Calculate surface normal using luminance as a heightmap
    float h = getLuma(source.rgb);
    float hR = getLuma(texture2D(tex, uv + vec2(texel.x, 0.0)).rgb);
    float hU = getLuma(texture2D(tex, uv + vec2(0.0, texel.y)).rgb);

    // Finite difference for normal estimation
    vec3 normal = normalize(vec3(h - hR, h - hU, bump_strength));

    // Animated light position circling above the center
    vec3 lp = vec3(0.5 + cos(time * 0.8) * 0.25, 0.5 + sin(time * 0.8) * 0.25, light_height);
    vec3 p = vec3(uv, 0.0);

    // Lighting vectors
    vec3 lightDir = normalize(lp - p);
    vec3 viewDir = vec3(0.0, 0.0, 1.0);
    vec3 reflectDir = reflect(-lightDir, normal);

    // Distance and Attenuation
    float dist = distance(lp, p);
    float atten = pow(clamp(1.0 - dist / light_size, 0.0, 1.0), 2.0);

    // Diffuse and Specular components
    float diff = max(dot(normal, lightDir), 0.0);
    float spec = pow(max(dot(viewDir, reflectDir), 0.0), shininess);

    // Combine lighting
    vec3 lighting = (diff * source.rgb + spec * 0.5) * light_color * atten;

    // Output illuminated part, rest is black (attenuation handles the falloff)
    return vec4(lighting, source.a);
}

// NAME: Edge Detection
uniform float threshold; // @min 0.0 @max 1.0 @default 0.1
uniform float thickness; // @min 0.5 @max 5.0 @default 1.0
uniform vec3 edge_color; // @default 1.0,1.0,1.0
uniform float background_mix; // @min 0.0 @max 1.0 @default 0.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 texel = thickness / resolution;

    // Sample neighbors
    vec4 center = texture2D(tex, uv);
    vec4 n1 = texture2D(tex, uv + vec2(texel.x, 0.0));
    vec4 n2 = texture2D(tex, uv + vec2(-texel.x, 0.0));
    vec4 n3 = texture2D(tex, uv + vec2(0.0, texel.y));
    vec4 n4 = texture2D(tex, uv + vec2(0.0, -texel.y));

    // Calculate color difference (gradient approximation)
    float diff = 0.0;
    diff += distance(n1.rgb, n2.rgb);
    diff += distance(n3.rgb, n4.rgb);

    // Apply threshold and smoothing
    float edge = smoothstep(threshold, threshold + 0.05, diff);

    // Combine edge with original image based on background_mix
    vec3 base = center.rgb * background_mix;
    vec3 finalRGB = mix(base, edge_color, edge);

    return vec4(finalRGB, center.a);
}

