    vec2 off = 1.0 / resolution.xy;

    // 2. Sample 9 pixels around the current coordinate (the "Kernel")
    float t00 = texture2D(tex0, uv + vec2(-off.x, -off.y)).r;
    float t10 = texture2D(tex0, uv + vec2( 0.0,   -off.y)).r;
    float t20 = texture2D(tex0, uv + vec2( off.x, -off.y)).r;
    float t01 = texture2D(tex0, uv + vec2(-off.x,  0.0)).r;
    float t21 = texture2D(tex0, uv + vec2( off.x,  0.0)).r;
    float t02 = texture2D(tex0, uv + vec2(-off.x,  off.y)).r;
    float t12 = texture2D(tex0, uv + vec2( 0.0,    off.y)).r;
    float t22 = texture2D(tex0, uv + vec2( off.x,  off.y)).r;

    // 3. Apply Sobel operators (Horizontal and Vertical)
    float gx = (t00 + 2.0 * t01 + t02) - (t20 + 2.0 * t21 + t22);
    float gy = (t00 + 2.0 * t10 + t20) - (t02 + 2.0 * t12 + t22);

    // 4. Calculate the edge intensity
    float edge = sqrt(gx * gx + gy * gy);

    // 5. ANIMATION: Make the lines "pulse" or "glow" using time
    // We use a sine wave to oscillate the edge thickness/intensity
    float pulse = edge * (0.5 + 0.5 * sin(time * 3.0));

    // 6. Output a neon line color (e.g., Cyan)
    vec3 lineColor = vec3(0.0, 1.0, 1.0) * pulse;

    gl_FragColor = vec4(lineColor, 1.0);
}

