uniform float lightRadius; // @min 0.1 @max 2.0 @default 0.6
uniform vec3 lightColor; // @default 1.0,0.9,0.8

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 baseColor = texture2D(tex, uv);
    vec2 off = 1.0 / resolution;

    // Sample neighbors for normal estimation
    float t00 = texture2D(tex, uv + vec2(-off.x, -off.y)).r;
    float t10 = texture2D(tex, uv + vec2( 0.0,   -off.y)).r;
    float t20 = texture2D(tex, uv + vec2( off.x, -off.y)).r;
    float t01 = texture2D(tex, uv + vec2(-off.x,  0.0)).r;
    float t21 = texture2D(tex, uv + vec2( off.x,  0.0)).r;
    float t02 = texture2D(tex, uv + vec2(-off.x,  off.y)).r;
    float t12 = texture2D(tex, uv + vec2( 0.0,    off.y)).r;
    float t22 = texture2D(tex, uv + vec2( off.x,  off.y)).r;

    // Sobel operator for bump mapping
    float gx = (t00 + 2.0 * t01 + t02) - (t20 + 2.0 * t21 + t22);
    float gy = (t00 + 2.0 * t10 + t20) - (t02 + 2.0 * t12 + t22);

    // Calculate surface normal
    vec3 normal = normalize(vec3(gx, gy, 0.5));

    // Generate random moving light position using noise
    vec2 lightPos = vec2(
        node_noise(vec2(time * 0.4, 1.23)),
        node_noise(vec2(4.56, time * 0.4))
    );

    // Calculate light direction and distance with aspect ratio correction
    vec2 diffPos = (lightPos - uv) * vec2(resolution.x / resolution.y, 1.0);
    vec3 lightDir = normalize(vec3(diffPos, lightZ));

    // Diffuse lighting
    float diff = max(dot(normal, lightDir), 0.0);

    // Attenuation (falloff)
    float dist = length(diffPos);
    float atten = smoothstep(lightRadius, 0.0, dist);

    // Combine to make only the lit area visible
    vec3 finalColor = baseColor.rgb * diff * atten * lightColor * 2.5;

    return vec4(finalColor, baseColor.a);
}

