// NAME: 3D Zooming Halftone Dots
uniform float zoom; // @min 0.1 @max 5.0 @default 1.5
uniform float zoomSpeed; // @min 0.0 @max 5.0 @default 0.5
uniform float dotScale; // @min 10.0 @max 200.0 @default 80.0
uniform vec3 bgColor; // @default 0.0,0.0,0.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 center = vec2(0.5);
    float currentZoom = zoom + sin(time * zoomSpeed) * 0.5;
    vec2 zoomedUv = center + (uv - center) / currentZoom;

    // Aspect ratio correction for perfectly round dots
    vec2 aspect = vec2(resolution.x / resolution.y, 1.0);
    vec2 gridUv = zoomedUv * aspect * dotScale;
    vec2 cellUv = fract(gridUv) - 0.5;
    vec2 cellId = (floor(gridUv) + 0.5) / (aspect * dotScale);

    // Check bounds to avoid wrapping artifacts
    if(cellId.x < 0.0 || cellId.x > 1.0 || cellId.y < 0.0 || cellId.y > 1.0) {
        return vec4(bgColor, 1.0);
    }

    vec4 texColor = texture2D(tex, cellId);
    float lum = dot(texColor.rgb, vec3(0.299, 0.587, 0.114));

    // Illuminated areas have small dots, dark areas have large dots (3D depth effect)
    float radius = mix(0.7, 0.05, lum);
    float dist = length(cellUv);

    float aa = 1.5 / dotScale; // Anti-aliasing based on scale
    float dotMask = smoothstep(radius + aa, radius - aa, dist);

    vec3 finalColor = mix(bgColor, texColor.rgb, dotMask);

    return vec4(finalColor, texColor.a);
}

