uniform float edgeSoftness; // @min 0.01 @max 1.0 @default 0.3
uniform float tintAmount; // @min 0.0 @max 1.0 @default 0.85
uniform float edgeWidth; // @min 0.5 @max 5.0 @default 1.0
uniform float darkThreshold; // @min 0.0 @max 1.0 @default 0.2
uniform float wiggleAmp; // @min 0.0 @max 0.1 @default 0.01
uniform float wiggleFreq; // @min 1.0 @max 50.0 @default 15.0
uniform float wiggleSpeed; // @min 0.0 @max 10.0 @default 3.0
uniform float blobRadius; // @min 0.0 @max 1.0 @default 0.2
uniform float blobSoftness; // @min 0.01 @max 1.0 @default 0.2
uniform float blobMoveRadius; // @min 0.0 @max 1.0 @default 0.2
uniform float blobMoveSpeed; // @min 0.0 @max 10.0 @default 2.0
uniform vec3 blobColor; // @default 0.0,0.0,0.0
uniform float gridScale; // @min 10.0 @max 500.0 @default 200.0
uniform float gridIntensity; // @min 0.0 @max 1.0 @default 0.6
uniform float gridSpeed; // @min 0.0 @max 5.0 @default 0.5
uniform float gridDistortion; // @min 0.0 @max 0.5 @default 0.05

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 texel = edgeWidth / resolution;
    vec4 c = texture2D(tex, uv);

    vec2 symUv = vec2(abs(uv.x - 0.5), uv.y - 0.5);
    vec2 wiggleOffset = vec2(
        sin(symUv.y * wiggleFreq + time * wiggleSpeed),
        cos(symUv.x * wiggleFreq + time * wiggleSpeed)
    ) * wiggleAmp;

    if (uv.x > 0.5) wiggleOffset.x = -wiggleOffset.x;

    vec2 wUv = uv + wiggleOffset;
    vec4 wc = texture2D(tex, wUv);
    vec4 n = texture2D(tex, wUv + vec2(0.0, texel.y));
    vec4 s = texture2D(tex, wUv - vec2(0.0, texel.y));
    vec4 e = texture2D(tex, wUv + vec2(texel.x, 0.0));
    vec4 w = texture2D(tex, wUv - vec2(texel.x, 0.0));

    vec4 diff = abs(wc - n) + abs(wc - s) + abs(wc - e) + abs(wc - w);
    float edge = length(diff.rgb) + diff.a;
    float isEdge = smoothstep(edgeThreshold, edgeThreshold + edgeSoftness, edge);

    float lum = dot(c.rgb, vec3(0.299, 0.587, 0.114));
    float darkFactor = smoothstep(0.0, darkThreshold, lum);

    float strobo = step(0.5, fract(time * 15.0));
    vec3 psychColor = mix(vec3(1.0, 0.4, 0.0), vec3(0.7, 0.0, 1.0), strobo);
    float swirl = sin(uv.x * 15.0 + time * 5.0) * cos(uv.y * 15.0 - time * 4.0);
    psychColor = clamp(psychColor + swirl * 0.3, 0.0, 1.0);

    vec4 tinted = mix(c, vec4(psychColor, c.a), tintAmount * darkFactor);

    vec2 aspectUv = symUv * vec2(resolution.x / resolution.y, 1.0);
    vec2 blobCenter = vec2(0.25 * (resolution.x / resolution.y), 0.0) + vec2(cos(time * blobMoveSpeed), sin(time * blobMoveSpeed)) * blobMoveRadius;
    float dist = distance(aspectUv, blobCenter);
    float blob = smoothstep(blobRadius, blobRadius + blobSoftness, dist);

    tinted.rgb = mix(blobColor, tinted.rgb, blob);

    vec4 finalColor = mix(tinted, wc, isEdge);

    // Zooming, Distorted, Symmetrical Grid with Growing Dots
    float zoom = 1.0 + 0.6 * sin(time * 1.5);
    vec2 gridUv = vec2(abs(uv.x - 0.5), uv.y);
    gridUv = (gridUv - vec2(0.25, 0.5)) * zoom + vec2(0.25, 0.5);
    gridUv.y -= time * gridSpeed; 
    gridUv += vec2(sin(gridUv.y * 15.0 + time), cos(gridUv.x * 15.0 + time)) * gridDistortion; 

    float gridX = sin(gridUv.x * gridScale);
    float gridY = sin(gridUv.y * gridScale);
    float dots = (gridX * gridY) * 0.5 + 0.5;

    float dotSize = 0.5 + 0.45 * sin(time * 3.0);
    float moire = smoothstep(1.0 - dotSize, 1.0 - dotSize + 0.1, dots);

    float mask = mix(1.0 - gridIntensity, 1.0 + gridIntensity, moire);
    finalColor.rgb *= mask;

    return finalColor;
}

