// NAME: Distorted Chromy Hue Scanner
uniform float rangeWidth; // @min 0.0 @max 1.0 @default 0.2
uniform float speed; // @min -2.0 @max 2.0 @default 0.5
uniform float p; // @min 0.0 @max 10.0 @default 5.0
uniform float dotGrid; // @min 1.0 @max 100.0 @default 10.0
uniform float dotSize; // @min 0.0 @max 2.0 @default 1.0
uniform float gridGrowth; // @min 0.0 @max 5.0 @default 1.0
uniform float dotspeed; // @min 0.0 @max 1.0 @default 0.2
uniform float distortion; // @min 0.0 @max 5.0 @default 1.5

vec3 rgb2hsv(vec3 c) {
    vec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);
    vec4 p_vec = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));
    vec4 q = mix(vec4(p_vec.xyw, c.r), vec4(c.r, p_vec.yzx), step(p_vec.x, c.r));
    float d = q.x - min(q.w, q.y);
    float e = 1.0e-10;
    return vec3(abs(q.z + (q.w - q.y) / (6.0 * d + e)), d / (q.x + e), q.x);
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);
    vec3 hsv = rgb2hsv(source.rgb);

    // Calculate the current hue target based on time and speed
    float targetHue = fract(time * speed);

    // Calculate the shortest distance on the circular hue spectrum (0.0 to 1.0)
    float dist = abs(fract(hsv.x - targetHue + 0.5) - 0.5);

    // Create a mask: 1.0 if within the range, 0.0 otherwise
    float mask = step(dist, rangeWidth * 0.5);

    // Adjust UV for perfect circles and center it
    vec2 aspect = vec2(resolution.x / resolution.y, 1.0);
    vec2 centeredUv = (uv - 0.5) * aspect;
    float distFromCenter = length(centeredUv);

    // Distort the grid as it goes far away from the center
    float angle = distFromCenter * distortion * 3.0 - time;
    float s = sin(angle);
    float c = cos(angle);
    vec2 distortedUv = centeredUv * mat2(c, s, -s, c); // Twist distortion
    // Add radial wave distortion that gets stronger further from the center
    distortedUv += normalize(centeredUv + 0.0001) * sin(distFromCenter * 15.0 - time * 4.0) * (distFromCenter * distFromCenter) * distortion * 0.5;

    // Make the grid shrink towards the center (going backward)
    float scale = exp(fract(time * gridGrowth) * 3.0);
    vec2 gridUv = distortedUv * dotGrid * scale;

    // Apply dotspeed to animate the dots within their grid cells
    vec2 dotUv = fract(gridUv + time * dotspeed * 0.1) - 0.5;

    // Make dots bigger further from the center, adjusting for the reversed scale
    float currentDotSize = dotSize * distFromCenter * 3.0 + (1.0 - 1.0 / scale) * 0.5 + 0.2;

    // Super blurred dots using a wide smoothstep
    float dots = 1.0 - smoothstep(0.0, currentDotSize * 2.0 + 0.1, length(dotUv));

    // Ensure black and dark pixels in the original image remain black
    float brightness = dot(source.rgb, vec3(0.299, 0.587, 0.114));
    float isNotBlack = smoothstep(0.05, 0.25, brightness);
    dots *= isNotBlack;

    // Create soft chromy inverted color
    vec3 invertedColor = 1.0 - source.rgb;
    float invLum = dot(invertedColor, vec3(0.299, 0.587, 0.114));
    vec3 chromyColor = 0.5 + 0.5 * sin(invLum * 12.0 + vec3(0.0, 2.0, 4.0));

    // Mix original color with the chromy dots based on the hue mask
    vec3 finalColor = mix(source.rgb, chromyColor * dots, mask);

    return vec4(finalColor, source.a);
}

