uniform float lineThickness; // @min 0.01 @max 0.5 @default 0.15
uniform vec3 snakeColor; // @default 0.0,1.0,0.5
uniform bool showBackground; // @default true

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);

    // Calculate luminance
    vec3 lumWeights = vec3(0.299, 0.587, 0.114);
    float lum = dot(source.rgb, lumWeights);

    // Calculate gradient to find the direction of the loops
    vec2 eps = vec2(2.0) / resolution;
    float lumX = dot(texture2D(tex, uv + vec2(eps.x, 0.0)).rgb, lumWeights);
    float lumY = dot(texture2D(tex, uv + vec2(0.0, eps.y)).rgb, lumWeights);
    vec2 grad = vec2(lumX - lum, lumY - lum);

    // Angle of the gradient (perpendicular to the isoline loop)
    float angle = atan(grad.y, grad.x);

    // Create closed loops (isolines) based on luminance
    float iso = fract(lum * linesCount);
    float lineMask = smoothstep(0.5 - lineThickness, 0.5, iso) - smoothstep(0.5, 0.5 + lineThickness, iso);

    // Fade out lines in completely flat areas where gradient is near zero
    float gradLen = length(grad);
    lineMask *= smoothstep(0.001, 0.01, gradLen);

    // Create the snake animation along the loop
    // Multiply tiling by 2.0 and floor it to ensure continuous loops without seams
    float tiling = floor(snakeTiling) * 2.0; 
    float snake = sin(angle * tiling + time * snakeSpeed);

    // Soften the snake head/tail
    float snakeMask = smoothstep(0.0, 0.8, snake);

    // Combine line and snake
    float finalMask = lineMask * snakeMask;

    // Mix with background
    vec3 bg = showBackground ? source.rgb : vec3(0.0);
    vec3 finalColor = mix(bg, snakeColor, finalMask);

    return vec4(finalColor, source.a);
}

