vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    // Sample original unwarped pixel
    vec4 origSource = texture2D(tex, uv);
    float origMax = max(max(origSource.r, origSource.g), origSource.b);
    float origMin = min(min(origSource.r, origSource.g), origSource.b);
    float origChroma = origMax - origMin;
    float origHue = 0.0;

    if (origChroma > 0.0) {
        if (origMax == origSource.r) origHue = (origSource.g - origSource.b) / origChroma;
        else if (origMax == origSource.g) origHue = 2.0 + (origSource.b - origSource.r) / origChroma;
        else origHue = 4.0 + (origSource.r - origSource.g) / origChroma;
        origHue *= 60.0;
        if (origHue < 0.0) origHue += 360.0;
    }

    bool isBlueOrViolet = origChroma > 0.05 && origHue >= 200.0 && origHue <= 330.0;

    // Reverse time for excluded colors to make the wave go in the opposite direction
