    float phase = waveDist * waveSpacing - localTime * waveSpeed;
    float wave = sin(phase);

    vec2 warpDir = mix(centerUv, vec2(0.0, 1.0), verticalWave);
    vec2 warp = uv + warpDir * wave * 0.04 * intensity;

    vec4 source = texture2D(tex, warp);

    // Psychedelic fractal generation
    vec2 uv_c = centerUv * 2.0;
    uv_c.x *= resolution.x / resolution.y;

