        uv_c = abs(uv_c) - 0.4;
        float a = localTime * 3.0 + length(uv_c) * 8.0;
        mat2 rot = mat2(cos(a), -sin(a), sin(a), cos(a));
        uv_c *= rot;
        uv_c *= 1.6;
