    float mask = smoothstep(blobSize + softness, blobSize - softness, d);

    // Pixelation effect
    vec2 pixUv = floor(uv * pixelation) / pixelation;

    // Blur the pixelated area
    vec4 blurColor = vec4(0.0);
    float total = 0.0;
    for(int x = -1; x <= 1; x++) {
        for(int y = -1; y <= 1; y++) {
            vec2 offset = vec2(float(x), float(y)) * blurRadius;
            blurColor += texture2D(tex, pixUv + offset);
            total += 1.0;
        }
    }
    blurColor /= total;

    // Original image
    vec4 source = texture2D(tex, uv);

    // Mix original image with the blurred, pixelated glob
    return mix(source, blurColor, mask);
