    float signedDist = fract(hsv.x - targetHue + 0.5) - 0.5;
    float dist = abs(signedDist);

    // Soften the mask to remove pixelated artifacts
    float mask = smoothstep(rangeWidth * 0.5 + edgeSoftness, rangeWidth * 0.5, dist);

