    float p1 = prime1;
    float p2 = prime2;
    float p3 = 5.0;
    float p5 = 11.0;

    // Scale radius to make the pattern smaller and denser
    float scaledR = r * spiralScale;

    // Spiral math using primes and custom parameters
    float spiral = a * p3 + scaledR * p1 - time * spiralSpeed;
    float mathBlob = sin(spiral) + cos(scaledR * p2 + a * p5) + sin(scaledR * p1 - time * p3);

    // Screen border mask to ensure it only affects the non-border part
    float borderMask = smoothstep(0.0, 0.15, uv.x) * smoothstep(1.0, 0.85, uv.x) * 
                       smoothstep(0.0, 0.15, uv.y) * smoothstep(1.0, 0.85, uv.y);

