    float borderMask = smoothstep(0.0, 0.15, uv.x) * smoothstep(1.0, 0.85, uv.x) * 
                       smoothstep(0.0, 0.15, uv.y) * smoothstep(1.0, 0.85, uv.y);

    float sizeMask = smoothstep(spiralSize, 0.05, r) * borderMask;
    float spot = smoothstep(0.5, 1.5, mathBlob) * sizeMask;
    float lsdEdge = smoothstep(lsdGlowWidth, 0.0, abs(mathBlob - 0.3)) * sizeMask;

    vec3 lsdColor = lineColor1;

    finalColor += lsdColor * lsdEdge * blackSpotAmount * 2.0;
    finalColor = mix(finalColor, vec3(0.0), spot * blackSpotAmount);

    vec2 lightPos = vec2(
        0.5 + 0.4 * sin(time * 1.1 + node_noise(vec2(time * 0.5, 0.0))),
        0.5 + 0.4 * cos(time * 1.3 + node_noise(vec2(0.0, time * 0.5)))
    );

    // Random movement different from the first light
    vec2 lightPos2 = vec2(
        0.5 + 0.4 * sin(time * 0.85 + node_noise(vec2(time * 0.2, 5.0)) * 10.0),
        0.5 + 0.4 * cos(time * 0.65 + node_noise(vec2(5.0, time * 0.2)) * 10.0)
    );

    vec2 lightUv = uv;
    lightUv.x *= resolution.x / resolution.y;

    vec2 lightPosAspect = lightPos;
    lightPosAspect.x *= resolution.x / resolution.y;

    vec2 lightPosAspect2 = lightPos2;
    lightPosAspect2.x *= resolution.x / resolution.y;

    float lDist = distance(lightUv, lightPosAspect);
    float lDist2 = distance(lightUv, lightPosAspect2);

    // Main light
    float illumination = pow(smoothstep(1.2, 0.0, lDist), 1.5);
    vec3 lightColor = vec3(1.0, 0.9, 0.7);

    finalColor *= illumination * (1.0 + lightColor * 2.5);

    if (blackLinesInLight) {
        float totalLines = clamp((edge * segment1 * 2.0) + (edge * segment2 * 1.5) + (lsdEdge * 2.0), 0.0, 1.0);
        finalColor = mix(finalColor, vec3(0.0), totalLines * illumination);
    }

    // Second light: low on the ground, invisible source, illuminates the surface with inverted colors
    float illumination2 = pow(smoothstep(0.8, 0.0, lDist2), 2.0);
    vec3 invertedBase = vec3(1.0) - baseColor.rgb;
    vec3 invertedLit = invertedBase * secondLightColor * 2.5;

    finalColor = mix(finalColor, invertedLit, illumination2);

    return vec4(finalColor, baseColor.a);
}

