uniform float speed; // @min -10.0 @max 10.0 @default 5.0
uniform float speed2; // @min -10.0 @max 10.0 @default 3.0
uniform float lineLength; // @min 1.0 @max 10.0 @default 1.0
uniform float delay; // @min 0.0 @max 5.0 @default 2.0
uniform float distOffset; // @min 0.0 @max 20.0 @default 10.0
uniform float centerBlur; // @min 0.0 @max 0.5 @default 0.1
uniform vec3 waveColor1; // @default 1.0,0.2,0.5
uniform vec3 waveColor2; // @default 0.2,0.8,1.0
uniform vec3 waveColor3; // @default 0.5,1.0,0.2
uniform float waveFreq; // @min 1.0 @max 50.0 @default 20.0
uniform float blackSpotAmount; // @min 0.0 @max 1.0 @default 0.8
uniform float spiralScale; // @min 5.0 @max 100.0 @default 40.0
uniform float spiralSpeed; // @min -20.0 @max 20.0 @default 7.0
uniform float spiralSize; // @min 0.05 @max 1.0 @default 0.3
uniform float lsdGlowWidth; // @min 0.1 @max 2.0 @default 0.8
uniform float prime1; // @min 1.0 @max 13.0 @default 2.0
uniform float prime2; // @min 1.0 @max 13.0 @default 3.0
uniform bool blackLinesInLight; // @default false
uniform vec3 secondLightColor; // @default 0.8,0.9,1.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 baseColor = texture2D(tex, uv);

    vec2 symUv = uv;
    float dir = 1.0;
    if (symUv.x > 0.5) {
        symUv.x = 1.0 - symUv.x;
        dir = -1.0;
    }

    float blob = node_noise(symUv * 5.0);
    float localTime = time;
    if (blob > 0.0) {
        localTime = time - delay;
    }

    vec2 off = 1.0 / resolution;

    float t00 = texture2D(tex, uv + vec2(-off.x, -off.y)).r;
    float t10 = texture2D(tex, uv + vec2( 0.0,   -off.y)).r;
    float t20 = texture2D(tex, uv + vec2( off.x, -off.y)).r;
    float t01 = texture2D(tex, uv + vec2(-off.x,  0.0)).r;
    float t21 = texture2D(tex, uv + vec2( off.x,  0.0)).r;
    float t02 = texture2D(tex, uv + vec2(-off.x,  off.y)).r;
    float t12 = texture2D(tex, uv + vec2( 0.0,    off.y)).r;
    float t22 = texture2D(tex, uv + vec2( off.x,  off.y)).r;

    float gx = (t00 + 2.0 * t01 + t02) - (t20 + 2.0 * t21 + t22);
    float gy = (t00 + 2.0 * t10 + t20) - (t02 + 2.0 * t12 + t22);

    float edge = sqrt(gx * gx + gy * gy);
    float angle = atan(gy, gx);

    float dist = distance(uv, vec2(0.5));

