// NAME: 3D Dual Light Spiral with Spherical Eye
uniform float speed; // @min -10.0 @max 10.0 @default 5.0
uniform float speed2; // @min -10.0 @max 10.0 @default 3.0
uniform float lineLength; // @min 1.0 @max 10.0 @default 1.0
uniform float distOffset; // @min 0.0 @max 20.0 @default 10.0
uniform vec3 waveColor1; // @default 1.0,0.2,0.5
uniform vec3 waveColor2; // @default 0.2,0.8,1.0
uniform vec3 waveColor3; // @default 0.5,1.0,0.2
uniform float waveFreq; // @min 1.0 @max 50.0 @default 20.0
uniform float spiralScale; // @min 5.0 @max 100.0 @default 40.0
uniform float spiralSpeed; // @min -20.0 @max 20.0 @default 7.0
uniform float spiralSize; // @min 0.05 @max 1.0 @default 0.3
uniform float eyeRange; // @min 0.0 @max 0.4 @default 0.15
uniform float eyeSize; // @min 0.05 @max 0.4 @default 0.2
uniform bool blackLinesInLight; // @default false
uniform vec3 secondLightColor; // @default 0.8,0.9,1.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 baseColor = texture2D(tex, uv);
    vec2 symUv = (uv.x > 0.5) ? vec2(1.0 - uv.x, uv.y) : uv;
    float dir = (uv.x > 0.5) ? -1.0 : 1.0;

    vec2 off = 1.0 / resolution;
    float t01 = texture2D(tex, uv + vec2(-off.x, 0.0)).r, t21 = texture2D(tex, uv + vec2(off.x, 0.0)).r;
    float t10 = texture2D(tex, uv + vec2(0.0, -off.y)).r, t12 = texture2D(tex, uv + vec2(0.0, off.y)).r;
    float gx = t01 - t21, gy = t10 - t12;
    float edge = sqrt(gx * gx + gy * gy) * 5.0;
    float angle = atan(gy, gx), dist = distance(uv, vec2(0.5));

    float seg1 = smoothstep(0.7, 0.95, sin(angle * lineLength + time * speed * dir - dist * distOffset));
    float seg2 = smoothstep(0.2, 0.8, sin(angle * lineLength - time * speed2 * dir - dist * distOffset * 0.7));

    vec3 lineColor1 = mix(waveColor1, waveColor2, sin(dist * waveFreq - time * speed) * 0.5 + 0.5);
    vec3 lineColor2 = mix(waveColor2, waveColor3, sin(dist * waveFreq * 0.6 + time * speed2) * 0.5 + 0.5);
    vec3 finalColor = baseColor.rgb * 0.4 + (lineColor1 * edge * seg1 * 2.0) + (lineColor2 * edge * seg2 * 1.5);

    vec2 centeredUv = (symUv - 0.5) * vec2(resolution.x / resolution.y, 1.0);
    float r = length(centeredUv), a = atan(centeredUv.y, centeredUv.x);
    float mathBlob = sin(a * 5.0 + r * spiralScale * 2.0 - time * spiralSpeed) + cos(r * 3.0 + a * 11.0);
    float sizeMask = smoothstep(spiralSize, 0.05, r) * smoothstep(0.0, 0.15, uv.x) * smoothstep(1.0, 0.85, uv.x);
    finalColor += lineColor1 * smoothstep(0.8, 0.0, abs(mathBlob - 0.3)) * sizeMask;
    finalColor = mix(finalColor, vec3(0.0), smoothstep(0.5, 1.5, mathBlob) * sizeMask * 0.8);

    vec2 lPos1 = vec2(0.5) + vec2(sin(time * 1.1), cos(time * 1.3)) * 0.4;
    vec2 lPos2 = vec2(0.5) + vec2(sin(time * 0.8), cos(time * 0.6)) * 0.4;
    vec2 aspectUv = uv * vec2(resolution.x / resolution.y, 1.0);
    float illu1 = pow(smoothstep(1.2, 0.0, distance(aspectUv, lPos1 * vec2(resolution.x / resolution.y, 1.0))), 1.5);
    float illu2 = pow(smoothstep(0.8, 0.0, distance(aspectUv, lPos2 * vec2(resolution.x / resolution.y, 1.0))), 2.0);

    finalColor *= illu1 * (1.0 + vec3(1.0, 0.9, 0.7) * 2.5);
    finalColor = mix(finalColor, (1.0 - baseColor.rgb) * secondLightColor * 2.5, illu2 * smoothstep(0.01, 0.05, dot(finalColor, vec3(0.3))));

    // Spherical Eye Logic
    vec2 eyePos = vec2(0.5) + vec2(sin(time * 0.7), cos(time * 0.9)) * eyeRange;
    vec2 eyePosAspect = eyePos * vec2(resolution.x / resolution.y, 1.0);
    float eyeDist = length(aspectUv - eyePosAspect);

    float eyeMask = smoothstep(eyeSize, eyeSize - 0.02, eyeDist);
    float pupilMask = smoothstep(eyeSize * 0.35, eyeSize * 0.35 - 0.02, eyeDist);
    vec3 eyeRender = mix(baseColor.rgb * 2.5, vec3(0.02), pupilMask);

    float totalIllum = clamp(illu1 + illu2, 0.0, 1.0);
    finalColor = mix(finalColor, eyeRender, eyeMask * totalIllum);
    finalColor += baseColor.rgb * 0.5 * pow(smoothstep(eyeSize * 2.5, 0.2, eyeDist), 2.0) * totalIllum;

    return vec4(finalColor, baseColor.a);
}

