    float localTime = time * (speed + source.r * 0.5) + (colorSeed * variation);
    float localZoom = zoom + (source.g * 3.0);
    float localPhase = source.b * 6.28;

    vec2 p = (uv - 0.5) * localZoom;
    p.x *= resolution.x / resolution.y;

    vec3 psychedelic = vec3(0.0);

    // Iterative folding fractal
    for (int i = 0; i < 5; i++) {
        float fi = float(i);

        // Rotation influenced by the specific color group
        float angle = localTime * 0.3 + fi * 1.047 + localPhase;
        float s = sin(angle);
        float c = cos(angle);
        p = vec2(p.x * c - p.y * s, p.x * s + p.y * c);

        // Mirroring and folding
        p = abs(p) - (0.4 + source.r * 0.2);
        if (p.x < p.y) {
            p = p.yx;
        }

        // Triangle distance field
        float d = max(abs(p.x) * 0.866025 + p.y * 0.5, -p.y);

        // Color cycling offset by the color seed
        psychedelic.r += sin(d * 10.0 + localTime + colorSeed) * 0.5 + 0.5;
        psychedelic.g += sin(d * 10.0 + localTime + 2.094 + colorSeed) * 0.5 + 0.5;
        psychedelic.b += sin(d * 10.0 + localTime + 4.188 + colorSeed) * 0.5 + 0.5;
    }

    // Normalize and blend with the original color intensity
    psychedelic /= 5.0;
    vec3 finalRGB = psychedelic * source.rgb * 2.5;

    return vec4(finalRGB, source.a);
}

// NAME: Quantized Color Psychedelia
uniform float speed; // @min 0.1 @max 5.0 @default 1.0
uniform float threshold; // @min 0.0 @max 1.0 @default 0.1
uniform float quantize; // @min 1.0 @max 20.0 @default 4.0
uniform float zoom; // @min 1.0 @max 10.0 @default 3.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);

    // 1. Parametric brightness threshold
    float brightness = (source.r + source.g + source.b) * 0.333;
    if (brightness < threshold) {
        return source;
    }

    // 2. Quantize color to create "ranges" or "groups" of pixels
    // This ensures pixels with similar colors are treated as a single block/group
    vec3 groupedColor = floor(source.rgb * quantize) / quantize;

    // 3. Generate a unique ID for this color group
    float groupID = node_rand(groupedColor.rg + groupedColor.b);

    // 4. Setup animation parameters based on the group ID
    float localTime = time * speed + (groupID * 20.0);
    vec2 p = (uv - 0.5) * zoom;
    p.x *= resolution.x / resolution.y;

    // 5. 4D Psychedelic Triangle Fractal
    vec3 psychedelic = vec3(0.0);
    for (int i = 0; i < 5; i++) {
        float fi = float(i);

        // Rotation varies per color group
        float angle = localTime * 0.2 + fi * 1.047 + (groupID * 6.28);
        float s = sin(angle);
        float c = cos(angle);
        p = vec2(p.x * c - p.y * s, p.x * s + p.y * c);

        // Mirroring and folding logic
        p = abs(p) - (0.3 + groupID * 0.2);
        if (p.x < p.y) {
            p = p.yx;
        }

        // Triangle distance field approximation
        float d = max(abs(p.x) * 0.866025 + p.y * 0.5, -p.y);

        // Color cycling offset by the group's unique ID
        psychedelic.r += sin(d * 8.0 + localTime + groupID) * 0.5 + 0.5;
        psychedelic.g += sin(d * 8.0 + localTime + 2.094 + groupID) * 0.5 + 0.5;
        psychedelic.b += sin(d * 8.0 + localTime + 4.188 + groupID) * 0.5 + 0.5;
    }

    // 6. Final composition
    psychedelic /= 5.0;

    // Blend the psychedelic pattern with the original source color intensity
    vec3 finalRGB = mix(source.rgb, psychedelic * 2.0, 0.8);

    return vec4(finalRGB, source.a);
}

// NAME: Advanced Color-Grouped Fractal
uniform float speed; // @min 0.1 @max 5.0 @default 1.0
uniform float threshold; // @min 0.0 @max 1.0 @default 0.1
uniform float quantize; // @min 1.0 @max 32.0 @default 8.0
uniform float zoom; // @min 1.0 @max 10.0 @default 3.0
uniform float contrast; // @min 0.0 @max 3.0 @default 1.2
uniform float brightness; // @min -0.5 @max 0.5 @default 0.0
uniform float saturation; // @min 0.0 @max 2.0 @default 1.1
uniform float shadows; // @min 0.5 @max 4.0 @default 1.2
uniform float psy_blend; // @min 0.0 @max 1.0 @default 0.7

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);

    // 1. Quantize color to create distinct ranges/groups
    vec3 groupedColor = floor(source.rgb * quantize) / quantize;
    float groupID = node_rand(groupedColor.rg + groupedColor.b);

    // 2. Parametric brightness threshold check
    float lum = dot(source.rgb, vec3(0.299, 0.587, 0.114));

    // 3. Setup fractal parameters
    float localTime = time * speed + (groupID * 12.34);
    vec2 p = (uv - 0.5) * zoom;
    p.x *= resolution.x / resolution.y;

    vec3 psychedelic = vec3(0.0);
    float shadowMask = 0.0;

    // 4. Fractal Loop
    for (int i = 0; i < 5; i++) {
        float fi = float(i);
        float angle = localTime * 0.2 + fi * 1.047 + (groupID * 6.28);
        float s = sin(angle);
        float c = cos(angle);
        p = vec2(p.x * c - p.y * s, p.x * s + p.y * c);

        // Mirroring and folding
        p = abs(p) - (0.3 + groupID * 0.15);
        if (p.x < p.y) p = p.yx;

        // Triangle distance field
        float d = max(abs(p.x) * 0.866025 + p.y * 0.5, -p.y);

        // Accumulate color and a "shadow" based on distance field edges
        psychedelic.r += sin(d * 10.0 + localTime) * 0.5 + 0.5;
        psychedelic.g += sin(d * 10.0 + localTime + 2.09) * 0.5 + 0.5;
        psychedelic.b += sin(d * 10.0 + localTime + 4.18) * 0.5 + 0.5;
        shadowMask += smoothstep(0.1, 0.0, abs(d - 0.2));
    }
    psychedelic /= 5.0;
    shadowMask /= 5.0;

    // 5. Blending logic based on threshold
    vec3 finalRGB;
    if (lum < threshold) {
        finalRGB = source.rgb;
    } else {
        // Apply fractal and internal "shader shadow"
        vec3 psyColor = psychedelic * 2.0;
        psyColor *= (1.0 - shadowMask * 0.5); // Internal fractal shadows
        finalRGB = mix(source.rgb, psyColor, psy_blend);
    }

    // 6. Global Image Adjustments
    // Shadows (Power curve)
    finalRGB = pow(max(finalRGB, 0.0), vec3(shadows));

    // Contrast
    finalRGB = (finalRGB - 0.5) * contrast + 0.5;

    // Brightness
    finalRGB += brightness;

    // Saturation
    float gray = dot(finalRGB, vec3(0.299, 0.587, 0.114));
    finalRGB = mix(vec3(gray), finalRGB, saturation);

    return vec4(clamp(finalRGB, 0.0, 1.0), source.a);
}

// NAME: Chrome Halo Fractal
uniform float speed; // @min 0.1 @max 5.0 @default 1.0
uniform float threshold; // @min 0.0 @max 1.0 @default 0.15
uniform float quantize; // @min 1.0 @max 32.0 @default 12.0
uniform float zoom; // @min 1.0 @max 10.0 @default 3.0
uniform float halo_strength; // @min 0.0 @max 2.0 @default 0.8
uniform float halo_spread; // @min 1.0 @max 10.0 @default 4.0
uniform float contrast; // @min 0.0 @max 3.0 @default 1.1
uniform float brightness; // @min -0.5 @max 0.5 @default 0.0
uniform float saturation; // @min 0.0 @max 2.0 @default 1.2
uniform float shadows; // @min 0.5 @max 4.0 @default 1.1
uniform float psy_blend; // @min 0.0 @max 1.0 @default 0.7

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);
    vec2 texel = 1.0 / resolution;

    // 1. Determine if current pixel is "Active" (above threshold)
    float lum = dot(source.rgb, vec3(0.299, 0.587, 0.114));
    bool isActive = lum >= threshold;

    // 2. Calculate Soft Halo for inactive pixels
    float halo = 0.0;
    if (!isActive && halo_strength > 0.0) {
        float samples = 0.0;
        // Sample 8 neighbors to find nearby active pixels
        for (int i = -1; i <= 1; i++) {
            for (int j = -1; j <= 1; j++) {
                if (i == 0 && j == 0) continue;
                vec2 offset = vec2(float(i), float(j)) * texel * halo_spread;
                vec3 neighbor = texture2D(tex, uv + offset).rgb;
                float nLum = dot(neighbor, vec3(0.299, 0.587, 0.114));
                halo += smoothstep(threshold - 0.05, threshold + 0.05, nLum);
                samples += 1.0;
            }
        }
        halo /= samples;
    }

    // 3. Fractal Logic for Active Pixels
    vec3 finalRGB;
    if (isActive) {
        vec3 groupedColor = floor(source.rgb * quantize) / quantize;
        float groupID = node_rand(groupedColor.rg + groupedColor.b);
        float localTime = time * speed + (groupID * 10.0);

        vec2 p = (uv - 0.5) * zoom;
        p.x *= resolution.x / resolution.y;

        vec3 psy = vec3(0.0);
        for (int i = 0; i < 4; i++) {
            float fi = float(i);
            float angle = localTime * 0.2 + fi * 1.047 + (groupID * 6.28);
            float s = sin(angle), c = cos(angle);
            p = vec2(p.x * c - p.y * s, p.x * s + p.y * c);
            p = abs(p) - (0.3 + groupID * 0.1);
            if (p.x < p.y) p = p.yx;
            float d = max(abs(p.x) * 0.866 + p.y * 0.5, -p.y);
            psy.r += sin(d * 12.0 + localTime) * 0.5 + 0.5;
            psy.g += sin(d * 12.0 + localTime + 2.09) * 0.5 + 0.5;
            psy.b += sin(d * 12.0 + localTime + 4.18) * 0.5 + 0.5;
        }
        finalRGB = mix(source.rgb, (psy / 4.0) * 2.0, psy_blend);
    } else {
        // Apply Halo to inactive pixels
        vec3 haloColor = 0.5 + 0.5 * cos(time * speed + vec3(0, 2, 4));
        finalRGB = mix(source.rgb, haloColor, halo * halo_strength);
    }

    // 4. Global Image Adjustments
    // Shadows
    finalRGB = pow(max(finalRGB, 0.0), vec3(shadows));
    // Contrast
    finalRGB = (finalRGB - 0.5) * contrast + 0.5;
    // Brightness
    finalRGB += brightness;
    // Saturation
    float gray = dot(finalRGB, vec3(0.299, 0.587, 0.114));
    finalRGB = mix(vec3(gray), finalRGB, saturation);

    return vec4(clamp(finalRGB, 0.0, 1.0), source.a);
}

// NAME: Selective Chrome Halo
