uniform vec3 halo_color; // @default 0.0,0.6,1.0
uniform float halo_strength; // @min 0.0 @max 2.0 @default 1.0
uniform float halo_spread; // @min 1.0 @max 15.0 @default 5.0
uniform float contrast; // @min 0.0 @max 3.0 @default 1.1
uniform float brightness; // @min -0.5 @max 0.5 @default 0.0
uniform float saturation; // @min 0.0 @max 2.0 @default 1.2
uniform float psy_blend; // @min 0.0 @max 1.0 @default 0.8

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);
    vec2 texel = 1.0 / resolution;

    // 1. Determine if current pixel is "Active" (above threshold)
    float lum = dot(source.rgb, vec3(0.299, 0.587, 0.114));
    bool isActive = lum >= threshold;

    vec3 finalRGB = vec3(0.0);
    float alpha = source.a;

    if (isActive) {
        // 2. Fractal Logic for Active Pixels
        vec3 groupedColor = floor(source.rgb * quantize) / quantize;
        float groupID = node_rand(groupedColor.rg + groupedColor.b);
        float localTime = time * speed + (groupID * 10.0);

        vec2 p = (uv - 0.5) * zoom;
        p.x *= resolution.x / resolution.y;

        vec3 psy = vec3(0.0);
        for (int i = 0; i < 4; i++) {
            float fi = float(i);
            float angle = localTime * 0.2 + fi * 1.047 + (groupID * 6.28);
            float s = sin(angle), c = cos(angle);
            p = vec2(p.x * c - p.y * s, p.x * s + p.y * c);
            p = abs(p) - (0.3 + groupID * 0.1);
            if (p.x < p.y) p = p.yx;
            float d = max(abs(p.x) * 0.866 + p.y * 0.5, -p.y);
            psy.r += sin(d * 12.0 + localTime) * 0.5 + 0.5;
            psy.g += sin(d * 12.0 + localTime + 2.09) * 0.5 + 0.5;
            psy.b += sin(d * 12.0 + localTime + 4.18) * 0.5 + 0.5;
        }
        finalRGB = mix(source.rgb, (psy / 4.0) * 2.0, psy_blend);
    } else {
        // 3. Calculate Soft Halo for inactive pixels
        float haloIntensity = 0.0;
        float samples = 0.0;
        // Sample neighbors to detect proximity to active pixels
        for (int i = -1; i <= 1; i++) {
            for (int j = -1; j <= 1; j++) {
                if (i == 0 && j == 0) continue;
                vec2 offset = vec2(float(i), float(j)) * texel * halo_spread;
                vec3 neighbor = texture2D(tex, uv + offset).rgb;
                float nLum = dot(neighbor, vec3(0.299, 0.587, 0.114));
                // Accumulate intensity if neighbor is above threshold
                haloIntensity += smoothstep(threshold - 0.05, threshold + 0.05, nLum);
                samples += 1.0;
            }
        }
        haloIntensity /= samples;

        // 4. Hide "the rest" - only show color if haloIntensity > 0
        if (haloIntensity > 0.001) {
            // Color the halo using the parameter and time-based shifting
            vec3 shiftingHalo = halo_color * (0.8 + 0.2 * sin(time * speed));
            finalRGB = shiftingHalo * haloIntensity * halo_strength;
        } else {
            // Completely hide pixels that are neither active nor in halo range
            return vec4(0.0, 0.0, 0.0, alpha);
        }
    }

    // 5. Global Image Adjustments (only applied to visible parts)
    // Contrast
    finalRGB = (finalRGB - 0.5) * contrast + 0.5;
    // Brightness
    finalRGB += brightness;
    // Saturation
    float gray = dot(finalRGB, vec3(0.299, 0.587, 0.114));
    finalRGB = mix(vec3(gray), finalRGB, saturation);

    return vec4(clamp(finalRGB, 0.0, 1.0), alpha);
}

// NAME: Looping Chrome Halo Fractal
uniform float speed; // @min 0.1 @max 2.0 @default 0.5
uniform float range_width; // @min 0.01 @max 0.5 @default 0.1
uniform float halo_strength; // @min 0.0 @max 2.0 @default 1.2
uniform float halo_spread; // @min 1.0 @max 10.0 @default 4.0
uniform vec3 halo_color; // @default 0.0,0.8,1.0
uniform float zoom; // @min 1.0 @max 10.0 @default 4.0
uniform float psy_blend; // @min 0.0 @max 1.0 @default 0.8
uniform float contrast; // @min 0.5 @max 2.0 @default 1.2
uniform float brightness; // @min -0.3 @max 0.3 @default 0.0
uniform float saturation; // @min 0.0 @max 2.0 @default 1.3

// Helper to determine if a pixel's color is within the currently active animated range
float getActivity(sampler2D t, vec2 uv, float target, float width) {
    vec3 c = texture2D(t, uv).rgb;
    float lum = dot(c, vec3(0.299, 0.587, 0.114));
    float diff = abs(lum - target);
    // Handle wrap-around for a smooth loop
    if (diff > 0.5) diff = 1.0 - diff;
    return smoothstep(width, width * 0.5, diff);
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);
    vec2 texel = 1.0 / resolution;

    // 1. Calculate the animated target color range (loops 0.0 to 1.0)
    float target = fract(time * speed * 0.2);

    // 2. Check activity of current pixel
    float active = getActivity(tex, uv, target, range_width);

    vec3 finalRGB = vec3(0.0);
    float alpha = source.a;

    if (active > 0.01) {
        // 3. Fractal Logic for pixels in the active color range
        // Quantize based on original color to group behaviors
        vec3 groupedColor = floor(source.rgb * 12.0) / 12.0;
        float groupID = node_rand(groupedColor.rg + groupedColor.b);
        float localTime = time * speed + (groupID * 10.0);

        vec2 p = (uv - 0.5) * zoom;
        p.x *= resolution.x / resolution.y;

        vec3 psy = vec3(0.0);
        for (int i = 0; i < 4; i++) {
            float fi = float(i);
            float angle = localTime * 0.2 + fi * 1.047 + (groupID * 6.28);
            float s = sin(angle), c = cos(angle);
            p = vec2(p.x * c - p.y * s, p.x * s + p.y * c);
            p = abs(p) - (0.3 + groupID * 0.1);
            if (p.x < p.y) p = p.yx;
            float d = max(abs(p.x) * 0.866 + p.y * 0.5, -p.y);
            psy.r += sin(d * 12.0 + localTime) * 0.5 + 0.5;
            psy.g += sin(d * 12.0 + localTime + 2.09) * 0.5 + 0.5;
            psy.b += sin(d * 12.0 + localTime + 4.18) * 0.5 + 0.5;
        }
        vec3 psyColor = (psy / 4.0) * 2.0;
        finalRGB = mix(source.rgb, psyColor, psy_blend * active);
    } else {
        // 4. Halo Logic for pixels outside the range but near it
        float haloIntensity = 0.0;
        // Sample 8 neighbors to find proximity to the active color range
        haloIntensity += getActivity(tex, uv + vec2(1, 1) * texel * halo_spread, target, range_width);
        haloIntensity += getActivity(tex, uv + vec2(-1, -1) * texel * halo_spread, target, range_width);
        haloIntensity += getActivity(tex, uv + vec2(1, -1) * texel * halo_spread, target, range_width);
        haloIntensity += getActivity(tex, uv + vec2(-1, 1) * texel * halo_spread, target, range_width);
        haloIntensity += getActivity(tex, uv + vec2(0, 1) * texel * halo_spread, target, range_width);
        haloIntensity += getActivity(tex, uv + vec2(0, -1) * texel * halo_spread, target, range_width);
        haloIntensity += getActivity(tex, uv + vec2(1, 0) * texel * halo_spread, target, range_width);
        haloIntensity += getActivity(tex, uv + vec2(-1, 0) * texel * halo_spread, target, range_width);
        haloIntensity /= 8.0;

        if (haloIntensity > 0.001) {
            // Apply colored halo and hide the original pixel
            vec3 dynamicHalo = halo_color * (0.7 + 0.3 * sin(time * speed * 2.0));
            finalRGB = dynamicHalo * haloIntensity * halo_strength;
        } else {
            // 5. Hide everything else
            return vec4(0.0, 0.0, 0.0, alpha);
        }
    }

    // 6. Global Post-Processing
    // Contrast
    finalRGB = (finalRGB - 0.5) * contrast + 0.5;
    // Brightness
    finalRGB += brightness;
    // Saturation
    float gray = dot(finalRGB, vec3(0.299, 0.587, 0.114));
    finalRGB = mix(vec3(gray), finalRGB, saturation);

    return vec4(clamp(finalRGB, 0.0, 1.0), alpha);
}

// NAME: Random Chrome Halo Fractal
uniform float speed; // @min 0.1 @max 2.0 @default 0.5
uniform float range_width; // @min 0.01 @max 0.5 @default 0.1
uniform float halo_strength; // @min 0.0 @max 3.0 @default 1.5
uniform float halo_spread; // @min 1.0 @max 15.0 @default 5.0
uniform vec3 halo_color; // @default 0.0,0.8,1.0
uniform float zoom; // @min 1.0 @max 10.0 @default 4.0
uniform float psy_blend; // @min 0.0 @max 1.0 @default 0.8
uniform float contrast; // @min 0.5 @max 2.0 @default 1.2
uniform float brightness; // @min -0.3 @max 0.3 @default 0.0
uniform float saturation; // @min 0.0 @max 2.0 @default 1.3

float getActivity(sampler2D t, vec2 uv, float target, float width) {
    vec3 c = texture2D(t, uv).rgb;
    float lum = dot(c, vec3(0.299, 0.587, 0.114));
    // Ensure absolute black pixels never trigger activity
    if (lum < 0.02) return 0.0;
    float diff = abs(lum - target);
    if (diff > 0.5) diff = 1.0 - diff;
    return smoothstep(width, width * 0.5, diff);
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);
    float origLum = dot(source.rgb, vec3(0.299, 0.587, 0.114));

    // CRITICAL: If original pixel is black, return black immediately
    if (origLum < 0.01) return vec4(0.0, 0.0, 0.0, source.a);

    vec2 texel = 1.0 / resolution;

    // 1. Randomly looping parameters using noise and sin
    float t_speed = time * speed;
    float dynSpread = halo_spread * (0.5 + 0.5 * node_noise(vec2(t_speed * 0.4, 1.0)));
    float dynStrength = halo_strength * (0.4 + 0.6 * node_noise(vec2(2.0, t_speed * 0.6)));

    // 2. Animated target color range
    float target = fract(t_speed * 0.2);
    float active = getActivity(tex, uv, target, range_width);

    vec3 finalRGB = vec3(0.0);

    if (active > 0.01) {
        // 3. Fractal Logic for active range
        vec3 groupedColor = floor(source.rgb * 10.0) / 10.0;
        float groupID = node_rand(groupedColor.rg + groupedColor.b);
        float localTime = time * speed + (groupID * 10.0);

        vec2 p = (uv - 0.5) * zoom;
        p.x *= resolution.x / resolution.y;

        vec3 psy = vec3(0.0);
        for (int i = 0; i < 4; i++) {
            float fi = float(i);
            float angle = localTime * 0.2 + fi * 1.047 + (groupID * 6.28);
            float s = sin(angle), c = cos(angle);
            p = vec2(p.x * c - p.y * s, p.x * s + p.y * c);
            p = abs(p) - (0.3 + groupID * 0.1);
            if (p.x < p.y) p = p.yx;
            float d = max(abs(p.x) * 0.866 + p.y * 0.5, -p.y);
            psy.r += sin(d * 12.0 + localTime) * 0.5 + 0.5;
            psy.g += sin(d * 12.0 + localTime + 2.09) * 0.5 + 0.5;
            psy.b += sin(d * 12.0 + localTime + 4.18) * 0.5 + 0.5;
        }
        finalRGB = mix(source.rgb, (psy / 4.0) * 2.0, psy_blend * active);
    } else {
        // 4. Dynamic Halo Logic
        float haloIntensity = 0.0;
        vec2 offsets[8];
        offsets[0] = vec2(1, 1);   offsets[1] = vec2(-1, -1);
        offsets[2] = vec2(1, -1);  offsets[3] = vec2(-1, 1);
        offsets[4] = vec2(0, 1);   offsets[5] = vec2(0, -1);
        offsets[6] = vec2(1, 0);   offsets[7] = vec2(-1, 0);

        for (int i = 0; i < 8; i++) {
            haloIntensity += getActivity(tex, uv + offsets[i] * texel * dynSpread, target, range_width);
        }
        haloIntensity /= 8.0;

        if (haloIntensity > 0.001) {
            vec3 dynamicColor = halo_color * (0.6 + 0.4 * sin(t_speed * 3.0 + origLum));
            finalRGB = dynamicColor * haloIntensity * dynStrength;
        } else {
            return vec4(0.0, 0.0, 0.0, source.a);
        }
    }

