// NAME: Hue Scanner PingPong Ease Dots
uniform float rangeWidth; // @min 0.0 @max 1.0 @default 0.2
uniform float speed; // @min -2.0 @max 2.0 @default 0.5
uniform float p; // @min 0.0 @max 10.0 @default 5.0
uniform float dotGrid; // @min 1.0 @max 100.0 @default 10.0
uniform float dotSize; // @min 0.0 @max 1.0 @default 0.5
uniform float dotsblur; // @min 0.0 @max 1.0 @default 0.5
uniform float gridGrowth; // @min 0.0 @max 5.0 @default 1.0
uniform float gridDistortion; // @min 0.0 @max 5.0 @default 2.0
uniform float colorFreq; // @min 0.1 @max 10.0 @default 2.0
uniform float colorSpeed; // @min -5.0 @max 5.0 @default 1.0
uniform float tint; // @min 0.0 @max 1.0 @default 0.5

vec3 rgb2hsv(vec3 c) {
    vec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);
    vec4 p_vec = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));
    vec4 q = mix(vec4(p_vec.xyw, c.r), vec4(c.r, p_vec.yzx), step(p_vec.x, c.r));
    float d = q.x - min(q.w, q.y);
    float e = 1.0e-10;
    return vec3(abs(q.z + (q.w - q.y) / (6.0 * d + e)), d / (q.x + e), q.x);
}

vec3 hsv2rgb(vec3 c) {
    vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
    vec3 p_vec = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
    return c.z * mix(K.xxx, clamp(p_vec - K.xxx, 0.0, 1.0), c.y);
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);
    vec3 hsv = rgb2hsv(source.rgb);

    // Calculate the current hue target based on time and speed
    float targetHue = fract(time * speed);

    // Calculate the shortest distance on the circular hue spectrum (0.0 to 1.0)
    float dist = abs(fract(hsv.x - targetHue + 0.5) - 0.5);

    // Create a mask: 1.0 if within the range, 0.0 otherwise
    float mask = step(dist, rangeWidth * 0.5);

    // Adjust UV for perfect circles and center it
    vec2 aspect = vec2(resolution.x / resolution.y, 1.0);
    vec2 centeredUv = (uv - 0.5) * aspect;
    float distFromCenter = length(centeredUv);

    // Make the grid grow and shrink from the center (ping-pong)
    float linearProgress = abs(fract(time * gridGrowth * 0.5) * 2.0 - 1.0);

    // Apply ease-in-out animation to the grid movement
    float loopProgress = smoothstep(0.0, 1.0, linearProgress);
    float scale = exp(-loopProgress * 3.0);

    // Fade in and out the dots at the extremes
    float fade = smoothstep(0.0, 0.2, loopProgress) * (1.0 - smoothstep(0.8, 1.0, loopProgress));

    // Distort the grid so cells (and dots) become larger further from the center
    float distortion = exp(-distFromCenter * gridDistortion);
    vec2 gridUv = centeredUv * dotGrid * scale * distortion;
    vec2 dotUv = fract(gridUv) - 0.5;

    // Make dots bigger further from the center, static size over time
    float currentDotSize = dotSize * distFromCenter * 2.0;

    // Use smoothstep to blur the dots based on the dotsblur uniform
    float dots = 1.0 - smoothstep(max(0.0, currentDotSize - dotsblur), currentDotSize + dotsblur + 0.001, length(dotUv));

    // Ensure black pixels in the original image remain black
    float isNotBlack = step(0.05, length(source.rgb));
    dots *= isNotBlack;

    // Scanner color applies where mask is 1.0, but cut out the dots (make them black)
    vec3 scannerColor = source.rgb * p * mask * (1.0 - dots);

    // Generate a color pattern based on distance from the center and mix with original based on tint
    vec3 generatedColor = hsv2rgb(vec3(distFromCenter * colorFreq - time * colorSpeed, 1.0, 1.0));
    vec3 dotPatternColor = mix(source.rgb, generatedColor, tint);

