    float edge = (distance(source.rgb, s_n.rgb) + distance(source.rgb, s_e.rgb)) * edge_boost;
    float trigger = edge * range_mask;

    // 4. Smooth Reactive Clouds
    vec2 p = (uv * 2.0 - 1.0) * vec2(resolution.x / resolution.y, 1.0);
    vec2 st = p * active_density + (source.rb - 0.5) * distortion;
    float t_anim = time * speed;
    float t_i = floor(t_anim);
    float t_f = fract(t_anim);

    float n1 = fbm_smooth(st, t_i);
    float n2 = fbm_smooth(st, t_i + 1.0);
