vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);
    float aspect = resolution.x / resolution.y;

    // Fractal space coordinates
    vec2 p = (uv - 0.5) * vec2(aspect, 1.0) * scale;
    float t = time * speed;

    // Fractal logic to generate dots and gravity vectors
    float d = 1.0;
    vec2 z = p;
    for (int i = 0; i < 5; i++) {
        float offset = 0.3 + 0.1 * sin(t * 0.7);
        z = abs(z) - offset;
        float ang = t * 0.4 + float(i) * 0.5;
        float s = sin(ang);
        float c = cos(ang);
        z = mat2(c, -s, s, c) * z;
        d = min(d, length(z));
    }

    // Fractal dots mask and color
    float mask = smoothstep(0.18, 0.0, d);
    vec3 fractalCol = 0.5 + 0.5 * cos(t + d * 10.0 + vec3(0.0, 2.0, 4.0));
    vec3 tintedColor = source.rgb * (vec3(1.0) + fractalCol * 1.5);

    // Shaking logic
    vec2 shake = vec2(
        node_noise(vec2(time * 10.0, 1.0)), 
        node_noise(vec2(time * 10.0, 2.0))
    ) * shakeAmount;

    // Gravity Warp: Pull the grid coordinates towards the fractal centers
    // (p - z) represents the displacement vector from the original point to the folded point
    // We use a falloff based on distance 'd' to create a localized gravity effect
    float gravityStrength = exp(-d * 3.0);
    vec2 gravityWarp = (p - z) * gravityStrength * 0.6;

    // Calculate grid UVs with shake and gravity distortion
    vec2 gridUv = uv * vec2(gridDensity * aspect, gridDensity) + shake + gravityWarp;

    // Calculate grid dots
    vec2 gPos = fract(gridUv) - 0.5;
    float gridDots = smoothstep(0.15, 0.05, length(gPos));

    // Mask grid by source brightness (black pixels have no grid)
    // We use a high multiplier to ensure even dark-grey pixels show the grid, but absolute black doesn't
    float brightness = clamp(length(source.rgb) * 10.0, 0.0, 1.0);
    vec3 finalGrid = vec3(gridDots) * source.a * brightness;

    // Blend fractal dots over the gravity-warped grid
    vec3 finalRGB = mix(finalGrid, tintedColor, mask * intensity);

    return vec4(finalRGB, source.a);
}

