uniform float maxSize; // @min 0.4 @max 1.0 @default 0.6
uniform float softness; // @min 0.01 @max 0.5 @default 0.1
uniform vec3 dotColor; // @default 1.0,1.0,1.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    float aspect = resolution.x / resolution.y;
    vec2 grid = vec2(density * aspect, density);

    // Calculate grid coordinates
    vec2 p = uv * grid;
    vec2 ip = floor(p);
    vec2 fp = fract(p) - 0.5;

    // Sample texture at the center of each dot cell
    vec2 sampleUv = (ip + 0.5) / grid;
    vec4 texCol = texture2D(tex, sampleUv);

    // Calculate brightness to influence dot size
    float brightness = dot(texCol.rgb, vec3(0.299, 0.587, 0.114));

    // Looping animation: size increases and then resets or pulses
    // Using a sine wave for a smooth continuous loop
    float pulse = 0.5 + 0.5 * sin(time * speed);
    float currentSize = mix(minSize, maxSize, pulse) * brightness;

    // Draw the dot using distance from cell center
    float dist = length(fp);
    float mask = smoothstep(currentSize, currentSize - softness, dist);

    // Combine dot mask with texture color and user-defined dot color
    vec3 finalRGB = texCol.rgb * dotColor * mask;
    float finalAlpha = texCol.a * mask;

    return vec4(finalRGB, finalAlpha);
}

// NAME: Shaken Blue Fractal Grid
uniform float speed; // @min 0.0 @max 2.0 @default 0.6
