uniform float dotSize; // @min 0.01 @max 0.5 @default 0.18
uniform float glowRange; // @min 0.1 @max 1.0 @default 0.6

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);
    float aspect = resolution.x / resolution.y;

    // Fractal space coordinates
    vec2 p = (uv - 0.5) * vec2(aspect, 1.0) * scale;
    float t = time * speed;

    // Fractal logic to generate distance field d
    float d = 1.0;
    vec2 z = p;
    for (int i = 0; i < 5; i++) {
        float offset = 0.4 + 0.15 * sin(t * 0.5);
        z = abs(z) - offset;
        float ang = t * 0.3 + float(i) * 0.8;
        float s = sin(ang);
        float c = cos(ang);
        z = mat2(c, -s, s, c) * z;
        d = min(d, length(z));
    }

    // Wide range mask with blue-tinted edges
    float mask = smoothstep(glowRange, 0.0, d);
    vec3 coreCol = 0.5 + 0.5 * cos(t + d * 8.0 + vec3(0.0, 2.0, 4.0));
    vec3 blueEdge = vec3(0.0, 0.3, 1.0) * 1.5;
    // Mix core color with a blue edge based on distance
    vec3 fractalCol = mix(blueEdge, coreCol, smoothstep(glowRange * 0.8, 0.0, d));
    vec3 tintedColor = source.rgb * (vec3(1.0) + fractalCol * 2.0);

    // Shake logic driven by the colored pixel intensity (mask)
    // Uses node_rand for high-frequency jitter where the color is strongest
    float noise = node_rand(uv + fract(time));
    vec2 dynamicShake = vec2(
        sin(time * 25.0 + uv.y * 10.0), 
        cos(time * 22.0 + uv.x * 10.0)
    ) * mask * shakeAmount * noise;

    // Gravity Warp: Pull the grid coordinates towards the fractal centers
    float gravityStrength = exp(-d * 2.5);
    vec2 gravityWarp = (p - z) * gravityStrength * 0.8;

    // Calculate grid UVs with mask-driven shake and gravity distortion
    vec2 gridUv = uv * vec2(gridDensity * aspect, gridDensity) + gravityWarp + dynamicShake;

    // Calculate grid dots
    vec2 gPos = fract(gridUv) - 0.5;
    float gridDots = smoothstep(dotSize, dotSize * 0.4, length(gPos));

    // Mask grid by source brightness and alpha
    float brightness = clamp(length(source.rgb) * 5.0, 0.0, 1.0);
    vec3 finalGrid = vec3(gridDots) * source.a * brightness;

    // Blend fractal colors over the warped grid
    // The mask is wider now, creating a more expansive colored area
    vec3 finalRGB = mix(finalGrid, tintedColor, mask * intensity);

    return vec4(finalRGB, source.a);
}

// NAME: Randomized Fractal Path
uniform float speed; // @min 0.0 @max 2.0 @default 0.6
uniform float scale; // @min 0.5 @max 10.0 @default 3.5
uniform float intensity; // @min 0.1 @max 2.0 @default 1.2
uniform float gridDensity; // @min 5.0 @max 50.0 @default 25.0
uniform float shakeAmount; // @min 0.0 @max 2.0 @default 0.6
uniform float dotSize; // @min 0.01 @max 0.5 @default 0.18
uniform float glowRange; // @min 0.1 @max 1.0 @default 0.7
uniform float randomness; // @min 0.0 @max 2.0 @default 1.2

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 source = texture2D(tex, uv);
    float aspect = resolution.x / resolution.y;
    float t = time * speed;

    // Fractal space coordinates with a bit of noise-driven drift
    vec2 drift = vec2(node_noise(vec2(t * 0.1, 0.0)), node_noise(vec2(0.0, t * 0.1))) * randomness * 0.2;
    vec2 p = (uv - 0.5 + drift) * vec2(aspect, 1.0) * scale;

    // Fractal logic with randomized iteration parameters
    float d = 1.0;
    vec2 z = p;
    for (int i = 0; i < 5; i++) {
        float fi = float(i);
        // Use noise to randomize the folding offset and rotation per iteration
        float noiseVal = node_noise(vec2(t * 0.2, fi * 1.5));
        float offset = 0.3 + 0.3 * noiseVal * randomness;

        z = abs(z) - offset;

        // Randomized rotation angle
        float ang = t * 0.3 + fi * 0.8 + (noiseVal * 2.0 - 1.0) * randomness;
        float s = sin(ang);
        float c = cos(ang);
        z = mat2(c, -s, s, c) * z;

        d = min(d, length(z));
    }

    // Wide range mask with randomized color shifting
    float mask = smoothstep(glowRange, 0.0, d);
    float colorNoise = node_noise(vec2(t * 0.5, d * 2.0)) * randomness;
    vec3 coreCol = 0.5 + 0.5 * cos(t + d * 12.0 + vec3(0.0, 2.0, 4.0) + colorNoise);
    vec3 blueEdge = vec3(0.1, 0.4, 1.0) * (1.0 + colorNoise);

    // Mix core color with a blue edge based on distance
    vec3 fractalCol = mix(blueEdge, coreCol, smoothstep(glowRange * 0.7, 0.0, d));
    vec3 tintedColor = source.rgb * (vec3(1.0) + fractalCol * 2.5);

    // High-frequency random shake driven by noise and mask
    float jitter = node_rand(uv + fract(time));
    vec2 dynamicShake = vec2(
        node_noise(vec2(t * 15.0, uv.y * 20.0)), 
        node_noise(vec2(uv.x * 20.0, t * 15.0))
    ) * mask * shakeAmount * jitter * randomness;

    // Gravity Warp: Pull the grid coordinates towards the fractal centers
    float gravityStrength = exp(-d * 3.0);
    vec2 gravityWarp = (p - z) * gravityStrength * 0.5;

    // Calculate grid UVs with randomized shake and gravity distortion
    vec2 gridUv = uv * vec2(gridDensity * aspect, gridDensity) + gravityWarp + dynamicShake;

    // Calculate grid dots
    vec2 gPos = fract(gridUv) - 0.5;
    float gridDots = smoothstep(dotSize, dotSize * 0.5, length(gPos));

    // Mask grid by source brightness and alpha
    float brightness = clamp(length(source.rgb) * 4.0, 0.0, 1.0);
    vec3 finalGrid = vec3(gridDots) * source.a * brightness;

    // Final blend
    vec3 finalRGB = mix(finalGrid, tintedColor, mask * intensity);

    return vec4(finalRGB, source.a);
}

