// NAME: Random Light Shadow BPM
uniform float bpm; // @min 1.0 @max 240.0 @default 120.0
uniform float light_z; // @min 0.01 @max 1.0 @default 0.15
uniform float intensity; // @min 0.0 @max 10.0 @default 5.0
uniform float ambient; // @min 0.0 @max 1.0 @default 0.1
uniform float bump; // @min 0.001 @max 0.2 @default 0.05
uniform float speed; // @min 0.1 @max 2.0 @default 1.0
uniform float lightspped; // @min 0.0 @max 10.0 @default 1.0
uniform float edge_glow; // @min 0.0 @max 5.0 @default 1.5
uniform float shadow_strength; // @min 0.0 @max 1.0 @default 0.8

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 texel = 1.0 / resolution;
    vec4 source = texture2D(tex, uv);

    // Calculate beat-based timing for light position jumps
    float beat = floor(time * (bpm / 60.0) * speed * lightspped);

    // Generate random light position per beat
    vec2 lp = vec2(
        node_rand(vec2(beat, 12.345)),
        node_rand(vec2(beat, 67.890))
    );

    // Luminance for bump mapping and shadow calculation
    vec3 lumWeight = vec3(0.299, 0.587, 0.114);
    float l = dot(source.rgb, lumWeight);
    float lx = dot(texture2D(tex, uv + vec2(texel.x, 0.0)).rgb, lumWeight);
    float ly = dot(texture2D(tex, uv + vec2(0.0, texel.y)).rgb, lumWeight);

    // Normal calculation
    vec2 grad = vec2(l - lx, l - ly);
    vec3 normal = normalize(vec3(grad, bump));

    // Lighting vectors
    vec3 lightPos3D = vec3(lp, light_z);
    vec3 fragPos3D = vec3(uv, l * bump);
    vec3 dir = normalize(lightPos3D - fragPos3D);

    // Shadow Raymarching (8 steps)
    float shadow = 1.0;
    float currentH = l * bump;
    vec2 rayStep = (lp - uv) * 0.125; // 1/8th steps

    for (int i = 1; i <= 8; i++) {
        vec2 sampleUv = uv + rayStep * float(i);
        float sampleHeight = dot(texture2D(tex, sampleUv).rgb, lumWeight) * bump;
        float rayHeight = mix(currentH, light_z, float(i) * 0.125);
        if (sampleHeight > rayHeight) {
            shadow = 1.0 - shadow_strength;
            break;
        }
    }

    // Attenuation and Diffuse
    float dist = distance(lightPos3D, fragPos3D);
    float atten = 1.0 / (1.0 + dist * dist * 20.0);
    float diff = max(dot(normal, dir), 0.0);

    // Edge detection for glow
    float edge = length(grad) * edge_glow * 10.0;

    // Final composition
    // Fixed: directLight must be a float to be added to ambient (float)
    float directLight = (diff * intensity * atten) * shadow;
    vec3 lighting = source.rgb * (ambient + directLight);

    // Fixed: lighting is vec3, so we must add a vec3
    lighting += vec3(edge * atten * intensity * shadow);

    return vec4(lighting, source.a);
}

