    vec3 lp = vec3(light_pos, light_z);
    vec3 p = vec3(uv, 0.0);
    vec3 dir = normalize(lp - p);

    // Distance attenuation
    float dist = distance(lp, p);
    float atten = 1.0 / (1.0 + dist * dist * 20.0);

    // Diffuse lighting calculation
    float diff = max(dot(normal, dir), 0.0);

    // Calculate saturation to specifically boost "colored parts"
    float maxC = max(source.r, max(source.g, source.b));
    float minC = min(source.r, min(source.g, source.b));
    float sat = (maxC - minC) / (maxC + 0.0001);

    // Combine lighting: ambient base + (diffuse * intensity * attenuation * saturation boost)
    // The (1.0 + sat) ensures colored parts receive more illumination than grayscale parts
    vec3 lightResult = source.rgb * (ambient + diff * intensity * atten * (1.0 + sat));

    return vec4(lightResult, source.a);
}

