uniform float speed; // @min 0.0 @max 100.0 @default 30.0
uniform float softness; // @min 0.0 @max 10.0 @default 4.0
uniform float sensitivity; // @min 0.0 @max 10.0 @default 5.0
uniform float depth_mult; // @min 0.0 @max 1.0 @default 0.4
uniform float shadow_threshold; // @min 0.0 @max 1.0 @default 0.1
uniform float shadow_contrast; // @min 0.0 @max 5.0 @default 2.0
uniform float glimmer; // @min 0.0 @max 1.0 @default 0.5

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 texel = 1.0 / max(resolution, vec2(1.0));
    vec4 base = texture2D(tex, uv);

    // Soften sampling for smoother normals and aura
    vec2 sO = texel * softness;
    vec4 s1 = texture2D(tex, uv + vec2(sO.x, 0.0));
    vec4 s2 = texture2D(tex, uv - vec2(sO.x, 0.0));
    vec4 s3 = texture2D(tex, uv + vec2(0.0, sO.y));
    vec4 s4 = texture2D(tex, uv - vec2(0.0, sO.y));
    vec4 blurred = (base + s1 + s2 + s3 + s4) * 0.2;

    // Calculate smooth surface normal
    vec3 lum = vec3(0.299, 0.587, 0.114);
    float h = dot(blurred.rgb, lum);
    float hx = dot(s1.rgb, lum);
    float hy = dot(s3.rgb, lum);
    vec3 n = normalize(vec3((h - hx) * depth_mult * 40.0, (h - hy) * depth_mult * 40.0, 0.2));

    float t = time * speed;

    // Reactive light vectors
    vec3 lr = normalize(vec3(sin(t + blurred.r * sensitivity), cos(t * 1.1), 0.6));
    vec3 lg = normalize(vec3(sin(t * 1.2 + blurred.g * sensitivity), cos(t * 0.8), 0.6));
    vec3 lb = normalize(vec3(sin(t * 0.9 + blurred.b * sensitivity), cos(t * 1.3), 0.6));

    // Per-channel diffuse lighting
    vec3 light;
    light.r = max(dot(n, lr), 0.0);
    light.g = max(dot(n, lg), 0.0);
    light.b = max(dot(n, lb), 0.0);

    // Apply shadow threshold and contrast
    light = max(vec3(0.0), light - shadow_threshold);
    light = pow(light, vec3(1.0 + shadow_contrast));

    // Add glimmer (specular element)
    float spec = pow(max(dot(n, vec3(0.0, 0.0, 1.0)), 0.0), 32.0) * glimmer;

    // Final composition
    // 1. Base texture lit by high-contrast light
    // 2. Soft aura bleed from blurred texture
    // 3. Glimmer highlights
    vec3 finalRGB = base.rgb * (light * 3.0 + 0.1);
    finalRGB += light * blurred.rgb * 1.2; 
    finalRGB += spec * light;

    return vec4(finalRGB, base.a);
}

