    // Using both x and y for the delay creates a diagonal wave effect
    float delay = (cellId.x + cellId.y) * animationDelay;
    float phase = fract(time * growSpeed + delay);

    // Calculate the current radius of the dot based on the animation phase
    float radius = phase * maxDistance;

    // Calculate the dot mask using distance from cell center
    float dist = length(localPos);
    // Smoothstep for anti-aliasing
    float dotMask = 1.0 - smoothstep(radius - 0.02, radius + 0.02, dist);

    // Determine if the pixel is "colored" (has enough brightness or alpha)
    float brightness = (source.r + source.g + source.b) / 3.0;
    float isColored = step(0.05, brightness) * step(0.05, source.a);

    // Apply the dot mask only to colored areas
    // Pixels that are not colored or are outside the dot radius become transparent/black
    return source * dotMask * isColored;
