uniform float animationDelay; // @min 0.0 @max 2.0 @default 0.2
uniform float inclination; // @min -1.0 @max 1.0 @default 0.3
uniform vec3 targetColor; // @default 1.0,0.3,0.0

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    // Apply horizontal symmetry to the UV coordinates
    vec2 symUv = vec2(0.5 - abs(uv.x - 0.5), uv.y);

    // Sample the original texture
    vec4 source = texture2D(tex, symUv);

    // Calculate aspect ratio for circular dots
    float aspect = resolution.x / resolution.y;

    // Setup grid coordinates with inclination
    vec2 gridUv = symUv * gridDensity;
    gridUv.x *= aspect;
    gridUv.x += gridUv.y * inclination;

    // Identify grid cell and local position
    vec2 cellId = floor(gridUv);
    vec2 localPos = fract(gridUv) - 0.5;

    // Calculate animation phase (0.0 to 1.0)
    float delay = (cellId.x + cellId.y) * animationDelay;
    float phase = fract(time * growSpeed + delay);

    // Size logic: phase determines radius
    float radius = phase * maxDistance;

    // Transparency logic: larger dots (higher phase) are more transparent
    float transparency = 1.0 - phase;

    // Color logic: color shifts from original to targetColor based on size (phase)
    vec3 dynamicColor = mix(source.rgb, targetColor, phase);

    // Dot mask calculation
    float dist = length(localPos);
    float dotMask = 1.0 - smoothstep(radius - 0.01, radius + 0.01, dist);

    // Combine everything
    // We multiply by source.a to respect the original texture's transparency
    float finalAlpha = source.a * transparency * dotMask;

    return vec4(dynamicColor, finalAlpha);
}

