// NAME: Dynamic Transparent Dot Grid
uniform float gridDensity; // @min 5.0 @max 100.0 @default 40.0
uniform float growSpeed; // @min 0.1 @max 5.0 @default 1.0
uniform float maxDistance; // @min 0.05 @max 0.5 @default 0.4
uniform float animationDelay; // @min 0.0 @max 2.0 @default 0.2
uniform float inclination; // @min -3.0 @max 6.0 @default 0.3

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    // Apply horizontal symmetry to the UV coordinates
    vec2 symUv = vec2(0.5 - abs(uv.x - 0.5), uv.y);

    // Sample the original texture using the mirrored UV
    vec4 source = texture2D(tex, symUv);

    // Calculate aspect ratio to keep dots circular
    float aspect = resolution.x / resolution.y;

    // Setup grid coordinates with aspect correction and inclination
    vec2 gridUv = symUv * gridDensity;
    gridUv.x *= aspect;
    gridUv.x += gridUv.y * inclination;

    // Identify the grid cell and local position within the cell
    vec2 cellId = floor(gridUv);
    vec2 localPos = fract(gridUv) - 0.5;

    // Calculate animation phase (0.0 to 1.0) with spatial delay
    float delay = (cellId.x + cellId.y) * animationDelay;
    float phase = fract(time * growSpeed + delay);

    // Calculate the current radius and the transparency factor
    // As phase increases, radius increases and transparency increases (alpha decreases)
    float radius = phase * maxDistance;
    float transparency = 1.0 - phase;

    // Calculate the dot mask using distance from cell center
    float dist = length(localPos);
    float dotMask = 1.0 - smoothstep(radius - 0.02, radius + 0.02, dist);

    // Determine if the pixel is "colored" based on source brightness/alpha
    float brightness = (source.r + source.g + source.b) / 3.0;
    float isColored = step(0.05, brightness) * step(0.05, source.a);

    // Change color based on size: interpolate towards a shifted version of the source color
    vec3 shiftedColor = mix(source.rgb, vec3(source.b, source.r, source.g), phase);

    // Combine color shift, transparency, and the dot mask
    vec4 finalColor = vec4(shiftedColor, source.a * transparency);

    return finalColor * dotMask * isColored;
}

