    // Make the UVs symmetrical horizontally
    vec2 symUv = vec2(uv.x > 0.5 ? 1.0 - uv.x : uv.x, uv.y);

    vec4 source = texture2D(tex, symUv);
    vec3 hsv = rgb2hsv(source.rgb);

    float targetHue = fract(time * speed);
    float dist = abs(fract(hsv.x - targetHue + 0.5) - 0.5);

