    float mask = smoothstep(rangeWidth * 0.5 + edgeSoftness, rangeWidth * 0.5, dist);

    // Create a much softer white border highlight around the masked area
    float border = smoothstep(borderSoftness, 0.0, abs(dist - rangeWidth * 0.5));

    // Parametric psychedelic shift
    float psychShift = sin(symUv.x * psychScale + time * 3.0) * psychIntensity + 
                       cos(symUv.y * psychScale - time * 2.0) * psychIntensity + time * 2.0;

