// NAME: Infinity Cube
uniform float size; // @min 0.1 @max 1.0 @default 0.5
uniform float thickness; // @min 0.005 @max 0.05 @default 0.01
uniform float speed; // @min 0.1 @max 3.0 @default 1.0
uniform vec3 cubeColor; // @default 0.0,0.8,1.0

mat2 node_rot(float a) {
    float s = sin(a), c = cos(a);
    return mat2(c, -s, s, c);
}

float sdFrame(vec3 p, float s, float e) {
    p = abs(p) - s;
    vec3 q = abs(p + e) - e;
    return min(min(
        length(max(vec3(p.x, q.y, q.z), 0.0)) + min(max(p.x, max(q.y, q.z)), 0.0),
        length(max(vec3(q.x, p.y, q.z), 0.0)) + min(max(q.x, max(p.y, q.z)), 0.0)),
        length(max(vec3(q.x, q.y, p.z), 0.0)) + min(max(q.x, max(q.y, p.z)), 0.0));
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec2 p = (uv - 0.5) * 2.0;
    p.x *= resolution.x / resolution.y;

    vec3 ro = vec3(0.0, 0.0, 2.5);
    vec3 rd = normalize(vec3(p, -1.5));

    float t = 0.0;
    float glow = 0.0;
    float d = 0.0;

    for(int i = 0; i < 32; i++) {
        vec3 pos = ro + rd * t;
        float dScene = 10.0;

        // Create 3 nested rotating frames
        for(int j = 0; j < 3; j++) {
            float fj = float(j);
            vec3 q = pos;
            q.xy *= node_rot(time * speed * (0.4 + fj * 0.15));
            q.xz *= node_rot(time * speed * (0.7 + fj * 0.1));
            float currentSize = size * (1.0 - fj * 0.25);
            dScene = min(dScene, sdFrame(q, currentSize, thickness));
        }

        d = dScene;
        if(d < 0.001 || t > 5.0) break;
        t += d;
        glow += 0.015 / (d + 0.04);
    }

    vec4 src = texture2D(tex, uv);
    vec3 col = cubeColor * glow;

    // Add a sharp edge highlight if we hit the surface
    if(d < 0.01) {
        col += cubeColor * 0.4;
    }

    return vec4(src.rgb + col, src.a);
}

