// NAME: Randomized Psychedelic Masked
uniform float velocity; // @min 0.1 @max 4.0 @default 1.0
uniform float phaseSpeed; // @min 0.05 @max 2.0 @default 0.3
uniform float intensity; // @min 0.0 @max 1.0 @default 0.8
uniform float darkThreshold; // @min 0.0 @max 1.0 @default 0.1
uniform float darkSoftness; // @min 0.01 @max 0.5 @default 0.2

mat2 rot(float a) {
    float s = sin(a), c = cos(a);
    return mat2(c, -s, s, c);
}

float fbm(vec2 p) {
    float v = 0.0, a = 0.5;
    for (int i = 0; i < 4; i++) {
        v += a * node_noise(p);
        p = rot(0.5) * p * 2.1;
        a *= 0.5;
    }
    return v;
}

vec2 kalei(vec2 p, float sides) {
    float a = atan(p.y, p.x);
    float r = length(p);
    float seg = 6.28318 / sides;
    a = abs(mod(a, seg) - seg * 0.5);
    return vec2(cos(a), sin(a)) * r;
}

vec3 pal(float t, vec3 d) {
    return 0.5 + 0.5 * cos(6.28318 * (vec3(1.0) * t + d));
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 texCol = texture2D(tex, uv);

    // Masking logic: preserve dark pixels
    float lum = dot(texCol.rgb, vec3(0.299, 0.587, 0.114));
    float mask = smoothstep(darkThreshold, darkThreshold + darkSoftness, lum);

    vec2 aspect = vec2(resolution.x / resolution.y, 1.0);
    vec2 p = (uv - 0.5) * aspect;
    float t = time * velocity;
    float pt = time * phaseSpeed;

    // Randomize phase weights using noise at different seeds
    float w0 = smoothstep(0.2, 0.8, node_noise(vec2(pt * 0.7, 1.1)));
    float w1 = smoothstep(0.2, 0.8, node_noise(vec2(pt * 0.8, 2.2)));
    float w2 = smoothstep(0.2, 0.8, node_noise(vec2(pt * 0.9, 3.3)));
    float w3 = smoothstep(0.2, 0.8, node_noise(vec2(pt * 1.0, 4.4)));
    float totalW = w0 + w1 + w2 + w3 + 0.001;

    // Distort coordinates for the psychedelic effect
    vec2 dp = p + 0.04 * vec2(fbm(p * 2.0 + t * 0.4), fbm(p * 2.0 - t * 0.3));
    float r = length(dp);
    float ang = atan(dp.y, dp.x);

    // Effect 1: Tunnel
    float tun = 0.5 + 0.5 * sin(8.0 * ang + 15.0 / (r + 0.02) - t * 4.0);
    // Effect 2: Chrysanthemum
    vec2 q = kalei(dp, 6.0 + 4.0 * node_noise(vec2(pt, 5.5)));
    float chr = fbm(q * 8.0 - t * 0.6) * exp(-r * 1.5);
    // Effect 3: Lattice
    vec2 lq = dp * rot(t * 0.15);
    for(int i=0; i<3; i++) { 
        lq = abs(kalei(lq, 5.0)) - 0.35; 
        lq *= rot(0.6); 
    }
    float lat = exp(-8.0 * abs(lq.x * lq.y));
    // Effect 4: Flow
    float flow = fbm(dp * 3.0 + vec2(t * 0.2, -t * 0.1));

    // Color Compositing
    vec3 c0 = pal(flow, vec3(0.0, 0.1, 0.2));
    vec3 c1 = pal(tun, vec3(0.1, 0.4, 0.7));
    vec3 c2 = pal(chr, vec3(0.8, 0.2, 0.3));
    vec3 c3 = pal(lat + r, vec3(0.6, 0.9, 0.1));

    vec3 col = (c0 * w0 + c1 * w1 + c2 * w2 + c3 * w3) / totalW;
    col += 0.12 * exp(-2.5 * r) * vec3(1.1, 1.0, 0.9); // Center glow

    // Post-processing
    col = 1.0 - exp(-col * 1.6);
    col *= smoothstep(1.4, 0.2, r); // Vignette
    col += (node_rand(uv + time) - 0.5) * 0.02; // Subtle grain

    // Final mix: only apply to bright areas of the original image
    return vec4(mix(texCol.rgb, col, intensity * mask), texCol.a);
}

