    float w1 = smoothstep(4.0, 12.0, ph) * (1.0 - smoothstep(20.0, 28.0, ph));
    float w2 = smoothstep(22.0, 30.0, ph) * (1.0 - smoothstep(40.0, 48.0, ph));
