uniform float trailLength; // @min 0.0 @max 2.0 @default 1.0
uniform float density; // @min 10.0 @max 100.0 @default 40.0
uniform float lineThreshold; // @min 0.0 @max 0.6 @default 0.2
uniform float edgeThickness; // @min 0.001 @max 0.02 @default 0.005
uniform float trackOffset; // @min -3.0 @max 3.0 @default 0.5
uniform float gapFrequency; // @min 0.05 @max 0.5 @default 0.15

// NEW: Color Targeting Sliders (Defaulted to Green)
uniform float targetR; // @min 0.0 @max 1.0 @default 0.3
uniform float targetG; // @min 0.0 @max 1.0 @default 0.6
uniform float targetB; // @min 0.0 @max 1.0 @default 0.2
uniform float colorTolerance; // @min 0.05 @max 1.5 @default 0.45

float getLuminance(vec3 color) {
    return dot(color, vec3(0.299, 0.587, 0.114));
}

float hash(vec3 p) {
    return fract(sin(dot(p, vec3(12.9898, 78.233, 45.543))) * 43758.5453);
}

vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {
    vec4 baseColor = texture2D(tex, uv);
    vec3 finalColor = baseColor.rgb; 

    // Protect the black lines from being painted over
    float currentLum = getLuminance(baseColor.rgb);
    bool isLine = currentLum < lineThreshold;

    float aspect = resolution.x / resolution.y;
    vec2 st = uv * vec2(aspect, 1.0);
    vec2 off = vec2(edgeThickness / aspect, edgeThickness);

    // Sobel Edge Detection
    float t00 = getLuminance(texture2D(tex, uv + vec2(-off.x, -off.y)).rgb);
    float t10 = getLuminance(texture2D(tex, uv + vec2( 0.0,   -off.y)).rgb);
    float t20 = getLuminance(texture2D(tex, uv + vec2( off.x, -off.y)).rgb);
    float t01 = getLuminance(texture2D(tex, uv + vec2(-off.x,  0.0)).rgb);
    float t21 = getLuminance(texture2D(tex, uv + vec2( off.x,  0.0)).rgb);
    float t02 = getLuminance(texture2D(tex, uv + vec2(-off.x,  off.y)).rgb);
    float t12 = getLuminance(texture2D(tex, uv + vec2( 0.0,    off.y)).rgb);
    float t22 = getLuminance(texture2D(tex, uv + vec2( off.x,  off.y)).rgb);

    float gx = (t00 + 2.0 * t01 + t02) - (t20 + 2.0 * t21 + t22);
    float gy = (t00 + 2.0 * t10 + t20) - (t02 + 2.0 * t12 + t22);
    float edge = length(vec2(gx, gy));

    float edgeZone = smoothstep(0.1, 0.4, edge);

    vec2 tangent = normalize(vec2(-gy, gx) + 0.00001);
    vec2 normal = normalize(vec2(gx, gy) + 0.00001);

    // --- COLOR TARGETING LOGIC ---
    // Look deeply inside the shape (along the normal) to find its actual color
    vec2 insideUv = uv + normal * (edgeThickness * 4.0);
    vec3 zoneColor = texture2D(tex, insideUv).rgb;

    // Check how close the zone's color is to our Target RGB sliders
    vec3 targetColor = vec3(targetR, targetG, targetB);
    float colorDist = distance(zoneColor, targetColor);
    bool inTargetZone = colorDist < colorTolerance;

    // Only do the math to draw dots if we are actually inside the correct color zone
    if (inTargetZone) {
        // Group the colors to give each shape a unique random starting offset
        vec3 zoneHashGroup = floor(zoneColor * 5.0) / 5.0;
        float travelPos = dot(st, tangent) * density - (time * speed) + hash(zoneHashGroup) * 100.0;

        // Offset the track so dots sit perfectly inside the color, not exactly on the line
        float crossPos = dot(st, normal) * density + trackOffset;

        float threshold = 1.0 - (dotSize * 0.5);

        float circleGrid = cos(travelPos) * cos(crossPos);
        float head = smoothstep(threshold, threshold + 0.1, circleGrid);

        float trailShape = cos(crossPos); 
        float trailMask = smoothstep(1.0 - trailLength, 1.0, cos(travelPos)) * smoothstep(0.0, 1.0, -sin(travelPos));
        float trail = smoothstep(threshold, threshold + 0.1, trailShape) * trailMask * 0.6;

        float sparsityMask = smoothstep(0.9, 1.0, cos(travelPos * gapFrequency));

        float comet = max(head, trail) * sparsityMask;
        float finalMask = comet * edgeZone;

        // Draw the red trace, but never paint over a dark line
        if (!isLine && finalMask > 0.01) {
            finalColor = mix(finalColor, vec3(1.0, 0.0, 0.0), finalMask);
        }
    }

    return vec4(finalColor, baseColor.a);
}

