uniform float whiteThreshold; // @min 0.4  @max 0.99  @default 0.85
uniform float trailSpeed;     // @min 0.0  @max 200.0 @default 50.0
uniform float trailLength;    // @min 0.01 @max 0.99  @default 0.65
