// ── 1. isEdgePixel ────────────────────────────────────────────────────────────
bool isEdgePixel(vec4 sp, float blackT, float whiteT) {
    return sp.a < 0.3
        || (sp.r < blackT && sp.g < blackT && sp.b < blackT)
        || (sp.r > whiteT && sp.g > whiteT && sp.b > whiteT);
}

// ── 2. marchRay ───────────────────────────────────────────────────────────────
float marchRay(sampler2D tex, vec2 uv, vec2 dir, vec2 px,
               float minD, float blackT, float whiteT,
               inout vec2 nearVec) {
    for (int j = 11; j <= 100; j++) {
        float fj = float(j);
        if (fj >= minD) break;
        vec2 s = uv + dir * px * fj;
        if (s.x < 0.0 || s.x > 1.0 || s.y < 0.0 || s.y > 1.0) {
            if (fj < minD) { minD = fj; nearVec = dir; }
            break;
        }
        if (isEdgePixel(texture2D(tex, s), blackT, whiteT)) {
            if (fj < minD) { minD = fj; nearVec = dir; }
            break;
        }
    }
    return minD;
}

// ── 3. sampleZoneColor ────────────────────────────────────────────────────────
vec3 sampleZoneColor(sampler2D tex, vec2 uv,
                     vec2 nearVec, vec2 px,
                     float minD, float zoneW, float maxD,
                     float blackT, float whiteT) {

    float zoneCenter = (floor(minD / zoneW) + 0.5) * zoneW;
    vec2  anchorUV   = uv + nearVec * px * (minD - zoneCenter);

    vec3  accum  = vec3(0.0);
    float weight = 0.0;

    for (int dy = -1; dy <= 1; dy++) {
        for (int dx = -1; dx <= 1; dx++) {
            vec2 s = anchorUV + vec2(float(dx), float(dy)) * px * 1.5;
            if (s.x < 0.0 || s.x > 1.0 || s.y < 0.0 || s.y > 1.0) continue;
            vec4 sc = texture2D(tex, s);
            if (isEdgePixel(sc, blackT, whiteT)) continue;
            if (sc.r < blackT && sc.g < blackT && sc.b < blackT && sc.a > 0.3) continue;
            accum  += sc.rgb;
            weight += 1.0;
        }
    }

    vec3  col       = (weight > 0.0) ? accum / weight : vec3(0.3);
    float depthFade = 1.0 - (zoneCenter / maxD) * 0.6;
    col *= depthFade * 0.65;
    return col;
}

// ── 4. processColor ───────────────────────────────────────────────────────────
vec4 processColor(sampler2D tex, vec2 uv, float time, vec2 resolution) {

    vec4 src = texture2D(tex, uv);

    bool srcIsBlack = src.r < blackThreshold && src.g < blackThreshold && src.b < blackThreshold && src.a > 0.3;
    bool srcIsBg    = src.r > whiteThreshold  && src.g > whiteThreshold  && src.b > whiteThreshold;
    bool srcIsShape = src.a > 0.3 && !srcIsBlack && !srcIsBg;

    if (srcIsBlack)             return vec4(0.0, 0.0, 0.0, 1.0);
    if (srcIsBg || !srcIsShape) return vec4(0.0, 0.0, 0.0, 0.0);

    float aspect = resolution.x / resolution.y;
    vec2  px     = vec2(0.001, 0.001 * aspect);

    float minD    = maxDepth;
    vec2  nearVec = vec2(1.0, 0.0);

    // ── Phase 1: Euclidean search ±10 ────────────────────────────────────────
    for (int dy = -10; dy <= 10; dy++) {
        for (int dx = -10; dx <= 10; dx++) {
            float fdx = float(dx), fdy = float(dy);
            float d2  = fdx*fdx + fdy*fdy;
            if (d2 < 0.5 || d2 > 100.5) continue;
            vec2  s  = uv + vec2(fdx, fdy) * px;
            float nd = sqrt(d2);
            if (s.x < 0.0 || s.x > 1.0 || s.y < 0.0 || s.y > 1.0) {
                if (nd < minD) { minD = nd; nearVec = normalize(vec2(fdx, fdy)); }
                continue;
            }
            if (isEdgePixel(texture2D(tex, s), blackThreshold, whiteThreshold))
                if (nd < minD) { minD = nd; nearVec = normalize(vec2(fdx, fdy)); }
        }
    }

    // ── Phase 2: 32-direction ray-march ──────────────────────────────────────
    if (minD > 10.0) {
        minD = marchRay(tex, uv, vec2( 1.0000, 0.0000), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2( 0.9808, 0.1951), px, minD, blackThreshold, whiteThreshold, nearVec);
