        minD = marchRay(tex, uv, vec2( 0.8315, 0.5556), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2( 0.7071, 0.7071), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2( 0.5556, 0.8315), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2( 0.3827, 0.9239), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2( 0.1951, 0.9808), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2( 0.0000, 1.0000), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2(-0.1951, 0.9808), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2(-0.3827, 0.9239), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2(-0.5556, 0.8315), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2(-0.7071, 0.7071), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2(-0.8315, 0.5556), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2(-0.9239, 0.3827), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2(-0.9808, 0.1951), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2(-1.0000, 0.0000), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2(-0.9808,-0.1951), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2(-0.9239,-0.3827), px, minD, blackThreshold, whiteThreshold, nearVec);
