        minD = marchRay(tex, uv, vec2( 0.9239,-0.3827), px, minD, blackThreshold, whiteThreshold, nearVec);
        minD = marchRay(tex, uv, vec2( 0.9808,-0.1951), px, minD, blackThreshold, whiteThreshold, nearVec);
