        float zoneDist  = abs(zoneNum - waveFront);
        visibility = 1.0 - smoothstep(animRadius * 0.5, animRadius, zoneDist);
        if (visibility < 0.001) return vec4(0.0, 0.0, 0.0, 0.0);
    }

