        col = mix(col, vec3(1.0), 0.95);
    } else if (phase < headSize + trailLength) {
        float t = (phase - headSize) / trailLength;
        col = mix(col, vec3(1.0), 0.88 * (1.0 - t * t));
    }

    return vec4(col, visibility);
