// ── 1. isEdgePixel ────────────────────────────────────────────────────────────
bool isEdgePixel(vec4 sp, float blackT, float whiteT) {
    return sp.a < 0.3
        || (sp.r < blackT && sp.g < blackT && sp.b < blackT)
        || (sp.r > whiteT && sp.g > whiteT && sp.b > whiteT);
}

// ── 2. marchRay ───────────────────────────────────────────────────────────────
float marchRay(sampler2D tex, vec2 uv, vec2 dir, vec2 px,
               float minD, float blackT, float whiteT,
               inout vec2 nearVec) {
    for (int j = 11; j <= 100; j++) {
        float fj = float(j);
        if (fj >= minD) break;
        vec2 s = uv + dir * px * fj;
        if (s.x < 0.0 || s.x > 1.0 || s.y < 0.0 || s.y > 1.0) {
            if (fj < minD) { minD = fj; nearVec = dir; }
            break;
        }
        if (isEdgePixel(texture2D(tex, s), blackT, whiteT)) {
            if (fj < minD) { minD = fj; nearVec = dir; }
            break;
        }
    }
    return minD;
}

// ── 3. sampleZoneColor ────────────────────────────────────────────────────────
vec3 sampleZoneColor(sampler2D tex, vec2 uv,
                     vec2 nearVec, vec2 px,
                     float minD, float zoneW, float maxD,
                     float blackT, float whiteT) {

    float zoneCenter = (floor(minD / zoneW) + 0.5) * zoneW;
    vec2  anchorUV   = uv + nearVec * px * (minD - zoneCenter);

    vec3  accum  = vec3(0.0);
    float weight = 0.0;

    for (int dy = -1; dy <= 1; dy++) {
        for (int dx = -1; dx <= 1; dx++) {
            vec2 s = anchorUV + vec2(float(dx), float(dy)) * px * 1.5;
            if (s.x < 0.0 || s.x > 1.0 || s.y < 0.0 || s.y > 1.0) continue;
