            if (isEdgePixel(sc, blackT, whiteT)) continue;
            if (sc.r < blackT && sc.g < blackT && sc.b < blackT && sc.a > 0.3) continue;
            accum  += sc.rgb;
            weight += 1.0;
        }
    }

    vec3  col       = (weight > 0.0) ? accum / weight : vec3(0.3);
    float depthFade = 1.0 - (zoneCenter / maxD) * 0.6;
    col *= depthFade * 0.65;
