// NAME: Zone Fractal + Hue Scanner
uniform float zoneWidth;      // @min 1.0  @max 80.0  @default 15.0
uniform float edgeWidth;      // @min 0.0  @max 10.0  @default 1.5
uniform float maxDepth;       // @min 10.0 @max 200.0 @default 100.0
uniform float blackThreshold; // @min 0.03 @max 0.6   @default 0.18
uniform float whiteThreshold; // @min 0.4  @max 0.99  @default 0.85
uniform float trailSpeed;     // @min 0.0  @max 200.0 @default 50.0
uniform float trailLength;    // @min 0.01 @max 0.99  @default 0.65
uniform float trailDistance;  // @min 1.0  @max 80.0  @default 15.0
uniform float scanSpeed;      // @min -2.0 @max 2.0   @default 0.4
uniform float rangeWidth;     // @min 0.0  @max 1.0   @default 0.25
uniform float edgeSoftness;   // @min 0.001 @max 0.5  @default 0.06
uniform float borderSoftness; // @min 0.001 @max 1.0  @default 0.15
uniform float borderBright;   // @min 0.0  @max 2.0   @default 1.2
uniform float symmetrical;    // @min 0.0  @max 1.0   @default 1.0

// ── rgb2hsv / hsv2rgb ─────────────────────────────────────────────────────────
vec3 rgb2hsv(vec3 c) {
    vec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);
    vec4 p = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));
    vec4 q = mix(vec4(p.xyw, c.r), vec4(c.r, p.yzx), step(p.x, c.r));
    float d = q.x - min(q.w, q.y);
    float e = 1.0e-10;
    return vec3(abs(q.z + (q.w - q.y) / (6.0 * d + e)), d / (q.x + e), q.x);
}

