    vec2 maskUV = uv;
    if (symmetrical > 0.5)
        maskUV.x = uv.x > 0.5 ? 1.0 - uv.x : uv.x;

    vec4 src = texture2D(tex, maskUV);
    vec3 hsv = rgb2hsv(src.rgb);

    float targetHue = fract(time * scanSpeed);
    float dist = abs(fract(hsv.x - targetHue + 0.5) - 0.5);

    float mask   = smoothstep(rangeWidth * 0.5 + edgeSoftness, rangeWidth * 0.5, dist);
    float border = smoothstep(borderSoftness, 0.0, abs(dist - rangeWidth * 0.5));

